import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { 
  Sparkles, 
  Send, 
  BarChart3, 
  Search, 
  Youtube, 
  Instagram, 
  Twitter, 
  Zap, 
  CheckCircle2, 
  AlertCircle, 
  Copy, 
  RefreshCcw,
  LayoutDashboard,
  Megaphone,
  Hash,
  MessageSquare,
  ArrowRight,
  Loader2
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

// --- Types & Constants ---

type Platform = 'youtube' | 'instagram' | 'tiktok' | 'twitter';

interface OptimisationData {
  score: number;
  sentiment: string;
  hookStrength: string;
  suggestions: string[];
  keywords: string[];
  alternativeTitles: string[];
  seoRating: number;
}

// --- Components ---

const PlatformButton = ({ 
  platform, 
  active, 
  onClick, 
  icon: Icon 
}: { 
  platform: Platform; 
  active: boolean; 
  onClick: () => void; 
  icon: any 
}) => (
  <button
    onClick={onClick}
    className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all ${
      active 
        ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' 
        : 'bg-white/5 text-slate-400 hover:bg-white/10'
    }`}
  >
    <Icon size={18} />
    <span className="capitalize text-sm font-medium">{platform}</span>
  </button>
);

const App = () => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [platform, setPlatform] = useState<Platform>('youtube');
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<OptimisationData | null>(null);
  const [error, setError] = useState<string | null>(null);

  const runOptimisation = async () => {
    if (!title.trim()) {
      setError("Please provide at least a title.");
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      const prompt = `
        Analyze the following creator content for ${platform}:
        Title: "${title}"
        Description/Script: "${description}"

        Provide a detailed optimization report in JSON format with the following structure:
        {
          "score": (number 0-100 overall optimization score),
          "sentiment": (string e.g. "Exciting", "Informative", "Urgent"),
          "hookStrength": (string "Low", "Medium", "High"),
          "suggestions": (array of strings for specific improvements),
          "keywords": (array of 8 relevant SEO tags/keywords),
          "alternativeTitles": (array of 3 better alternatives),
          "seoRating": (number 0-100)
        }
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              score: { type: Type.NUMBER },
              sentiment: { type: Type.STRING },
              hookStrength: { type: Type.STRING },
              suggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
              keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
              alternativeTitles: { type: Type.ARRAY, items: { type: Type.STRING } },
              seoRating: { type: Type.NUMBER },
            },
            required: ['score', 'sentiment', 'hookStrength', 'suggestions', 'keywords', 'alternativeTitles', 'seoRating']
          }
        },
      });

      const data = JSON.parse(response.text);
      setResults(data);
    } catch (err) {
      console.error(err);
      setError("Failed to process optimisation. Please check your inputs.");
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    // Could add a toast here
  };

  return (
    <div className="min-h-screen p-4 md:p-8 flex flex-col items-center max-w-7xl mx-auto">
      {/* Header */}
      <header className="w-full flex justify-between items-center mb-10">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl">
            <Sparkles className="text-white" size={24} />
          </div>
          <h1 className="text-2xl font-heading font-bold tracking-tight">
            Creator <span className="gradient-text">Optimisation</span>
          </h1>
        </div>
        <div className="flex gap-4">
          <div className="hidden md:flex items-center gap-2 px-3 py-1.5 rounded-full bg-white/5 border border-white/10 text-xs font-medium text-slate-400">
            <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
            AI Engine Active
          </div>
        </div>
      </header>

      {/* Main Grid */}
      <div className="w-full grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">

        {/* PANEL 1: Creation Studio */}
        <section className="glass rounded-3xl p-6 md:p-8 space-y-8 shadow-2xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-8 opacity-5 pointer-events-none group-hover:opacity-10 transition-opacity">
            <LayoutDashboard size={120} />
          </div>

          <div className="flex items-center gap-2 mb-2">
            <Zap size={20} className="text-indigo-400" />
            <h2 className="text-xl font-bold">Studio Workspace</h2>
          </div>

          {/* Platform Select */}
          <div className="space-y-3">
            <label className="text-sm font-medium text-slate-400">Target Platform</label>
            <div className="flex flex-wrap gap-2">
              <PlatformButton 
                platform="youtube" 
                active={platform === 'youtube'} 
                onClick={() => setPlatform('youtube')} 
                icon={Youtube} 
              />
              <PlatformButton 
                platform="instagram" 
                active={platform === 'instagram'} 
                onClick={() => setPlatform('instagram')} 
                icon={Instagram} 
              />
              <PlatformButton 
                platform="tiktok" 
                active={platform === 'tiktok'} 
                onClick={() => setPlatform('tiktok')} 
                icon={MessageSquare} 
              />
              <PlatformButton 
                platform="twitter" 
                active={platform === 'twitter'} 
                onClick={() => setPlatform('twitter')} 
                icon={Twitter} 
              />
            </div>
          </div>

          {/* Content Inputs */}
          <div className="space-y-6">
            <div className="space-y-2">
              <div className="flex justify-between items-center">
                <label className="text-sm font-medium text-slate-400">Title / Headline</label>
                <span className={`text-[10px] ${title.length > 70 ? 'text-amber-400' : 'text-slate-500'}`}>
                  {title.length}/70
                </span>
              </div>
              <input 
                type="text" 
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                placeholder="Hooky title or video topic..."
                className="w-full bg-slate-900/50 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all placeholder:text-slate-600"
              />
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-400">Description or Script Snippet</label>
              <textarea 
                rows={6}
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                placeholder="Paste your video description, script intro, or tweet thread content..."
                className="w-full bg-slate-900/50 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all placeholder:text-slate-600 resize-none"
              />
            </div>
          </div>

          <button 
            onClick={runOptimisation}
            disabled={loading}
            className={`w-full py-4 rounded-xl flex items-center justify-center gap-2 font-bold transition-all ${
              loading 
                ? 'bg-slate-800 text-slate-500 cursor-not-allowed' 
                : 'bg-indigo-600 hover:bg-indigo-500 text-white pulse-glow shadow-indigo-600/20'
            }`}
          >
            {loading ? (
              <>
                <Loader2 className="animate-spin" size={20} />
                Analysing Trends...
              </>
            ) : (
              <>
                <Send size={20} />
                Run AI Optimisation
              </>
            )}
          </button>

          {error && (
            <div className="flex items-center gap-2 p-3 rounded-lg bg-red-500/10 border border-red-500/20 text-red-400 text-sm">
              <AlertCircle size={16} />
              {error}
            </div>
          )}
        </section>

        {/* PANEL 2: Optimization Hub */}
        <section className={`glass rounded-3xl p-6 md:p-8 transition-all min-h-[600px] flex flex-col ${!results ? 'justify-center items-center' : ''}`}>
          {!results && !loading && (
            <div className="text-center space-y-4 opacity-40">
              <div className="mx-auto w-16 h-16 rounded-full bg-white/5 flex items-center justify-center">
                <BarChart3 size={32} />
              </div>
              <p className="max-w-xs mx-auto text-sm">
                Enter your content details on the left to generate an AI performance report.
              </p>
            </div>
          )}

          {loading && (
            <div className="w-full h-full flex flex-col items-center justify-center space-y-6">
              <div className="relative">
                <div className="w-20 h-20 border-4 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center">
                  <Sparkles className="text-indigo-400 animate-pulse" size={24} />
                </div>
              </div>
              <div className="text-center">
                <h3 className="text-xl font-bold">Analysing Hook Strength</h3>
                <p className="text-slate-400 text-sm">Scoring SEO potential and generating alternatives...</p>
              </div>
            </div>
          )}

          {results && !loading && (
            <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="flex justify-between items-start">
                <div>
                  <h2 className="text-2xl font-bold flex items-center gap-2">
                    <Megaphone className="text-pink-400" size={22} />
                    Optimization Report
                  </h2>
                  <p className="text-slate-400 text-sm mt-1">Based on current algorithmic trends for {platform}</p>
                </div>
                <div className="relative w-24 h-24 flex items-center justify-center">
                  <svg className="w-full h-full -rotate-90">
                    <circle 
                      cx="48" cy="48" r="40" 
                      className="fill-none stroke-slate-800 stroke-[8]"
                    />
                    <circle 
                      cx="48" cy="48" r="40" 
                      className="fill-none stroke-indigo-500 stroke-[8]"
                      strokeDasharray={251}
                      strokeDashoffset={251 - (251 * results.score) / 100}
                      strokeLinecap="round"
                    />
                  </svg>
                  <div className="absolute inset-0 flex flex-col items-center justify-center">
                    <span className="text-2xl font-bold">{results.score}</span>
                    <span className="text-[10px] text-slate-500">SCORE</span>
                  </div>
                </div>
              </div>

              {/* Quick Stats Grid */}
              <div className="grid grid-cols-2 gap-4">
                <div className="p-4 rounded-2xl bg-white/5 border border-white/10">
                  <span className="text-xs text-slate-500 uppercase tracking-wider block mb-1">Sentiment</span>
                  <div className="text-lg font-bold text-indigo-300">{results.sentiment}</div>
                </div>
                <div className="p-4 rounded-2xl bg-white/5 border border-white/10">
                  <span className="text-xs text-slate-500 uppercase tracking-wider block mb-1">Hook Strength</span>
                  <div className="flex items-center gap-2">
                    <span className={`text-lg font-bold ${
                      results.hookStrength === 'High' ? 'text-green-400' : 
                      results.hookStrength === 'Medium' ? 'text-amber-400' : 'text-red-400'
                    }`}>
                      {results.hookStrength}
                    </span>
                    {results.hookStrength === 'High' && <CheckCircle2 size={16} className="text-green-400" />}
                  </div>
                </div>
              </div>

              {/* AI Suggestions */}
              <div className="space-y-3">
                <h3 className="text-sm font-semibold uppercase tracking-widest text-slate-500">Recommended Fixes</h3>
                <div className="space-y-2">
                  {results.suggestions.map((s, i) => (
                    <div key={i} className="flex gap-3 items-start p-3 rounded-xl bg-indigo-500/5 border border-indigo-500/10 group">
                      <div className="w-5 h-5 rounded-full bg-indigo-500/20 flex items-center justify-center mt-0.5 shrink-0">
                        <ArrowRight size={12} className="text-indigo-400" />
                      </div>
                      <p className="text-sm text-slate-300 leading-relaxed">{s}</p>
                    </div>
                  ))}
                </div>
              </div>

              {/* Title Variations */}
              <div className="space-y-3">
                <h3 className="text-sm font-semibold uppercase tracking-widest text-slate-500">A/B Title Variations</h3>
                <div className="grid gap-2">
                  {results.alternativeTitles.map((t, i) => (
                    <div key={i} className="flex items-center justify-between p-3 rounded-xl bg-slate-900/50 border border-white/5 group hover:border-white/20 transition-all cursor-pointer" onClick={() => copyToClipboard(t)}>
                      <span className="text-sm font-medium">{t}</span>
                      <Copy size={14} className="text-slate-500 group-hover:text-indigo-400 transition-colors" />
                    </div>
                  ))}
                </div>
              </div>

              {/* Keywords */}
              <div className="space-y-3">
                <h3 className="text-sm font-semibold uppercase tracking-widest text-slate-500">Optimized Tags</h3>
                <div className="flex flex-wrap gap-2">
                  {results.keywords.map((k, i) => (
                    <span key={i} className="px-3 py-1 rounded-full bg-white/5 border border-white/10 text-xs text-slate-400 flex items-center gap-1 hover:bg-white/10 transition-colors cursor-default">
                      <Hash size={10} />
                      {k}
                    </span>
                  ))}
                </div>
              </div>
            </div>
          )}
        </section>
      </div>

      {/* Footer Info */}
      <footer className="mt-12 text-slate-500 text-sm flex items-center gap-6">
        <div className="flex items-center gap-2">
          <Sparkles size={14} className="text-indigo-500" />
          <span>Powered by Gemini 3 Flash</span>
        </div>
        <div className="w-1 h-1 rounded-full bg-slate-700"></div>
        <span>© 2024 Optimisation Lab</span>
      </footer>
    </div>
  );
};

const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(<App />);
}

{
  "description": "Creator Optimisation: A high-performance dashboard for content creators to analyze and optimize their video titles, scripts, and SEO metadata using Gemini AI."
