} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

// --- Types ---

type Platform = 'youtube' | 'instagram' | 'tiktok' | 'twitter';

interface OptimisationData {
  score: number;
  sentiment: string;
  hookStrength: string;
  suggestions: string[];
  keywords: string[];
  alternativeTitles: string[];
  seoRating: number;
}

// --- UI Components ---

const SidebarItem = ({ icon: Icon, label, active = false }: { icon: any, label: string, active?: boolean }) => (
  <div className={`flex items-center gap-3 px-4 py-3 rounded-xl cursor-pointer transition-all ${active ? 'bg-indigo-600/10 text-indigo-400 border border-indigo-500/20' : 'text-slate-500 hover:bg-white/5'}`}>
    <Icon size={20} />
    <span className="font-medium text-sm">{label}</span>
  </div>
);

const StatBadge = ({ icon: Icon, label, value, color }: { icon: any, label: string, value: string | number, color: string }) => (
  <div className="bg-slate-900/50 border border-white/5 rounded-2xl p-4 flex flex-col gap-1">
    <div className="flex items-center gap-2 text-slate-500 mb-1">
      <Icon size={14} className={color} />
      <span className="text-[10px] uppercase font-bold tracking-wider">{label}</span>
    </div>
    <div className="text-xl font-bold">{value}</div>
  </div>
);

const App = () => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [platform, setPlatform] = useState<Platform>('youtube');
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<OptimisationData | null>(null);
  const [error, setError] = useState<string | null>(null);
