  const runOptimisation = async () => {
    if (!title.trim()) {
      setError("Title is required for analysis.");
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      const prompt = `
        Analyze this creator content for ${platform}:
        Title: "${title}"
        Description: "${description}"

        Return a JSON report:
        {
          "score": (0-100),
          "sentiment": "e.g. High Energy",
          "hookStrength": "Low/Medium/High",
          "suggestions": ["suggestion1", "suggestion2"],
          "keywords": ["tag1", "tag2", "tag3"],
          "alternativeTitles": ["alt1", "alt2"],
          "seoRating": (0-100)
        }
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              score: { type: Type.NUMBER },
              sentiment: { type: Type.STRING },
              hookStrength: { type: Type.STRING },
              suggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
              keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
              alternativeTitles: { type: Type.ARRAY, items: { type: Type.STRING } },
              seoRating: { type: Type.NUMBER },
            },
            required: ['score', 'sentiment', 'hookStrength', 'suggestions', 'keywords', 'alternativeTitles', 'seoRating']
          }
        },
      });

      const data = JSON.parse(response.text);
      setResults(data);
    } catch (err) {
      setError("AI analysis failed. Check connection.");
