import React, { useState, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { 
  Sparkles, 
  Image as ImageIcon, 
  Upload, 
  Copy, 
  Check, 
  ArrowRight, 
  Loader2, 
  Type, 
  Hash, 
  Smartphone,
  ChevronRight,
  RefreshCw,
  ShoppingBag,
  Zap
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

// --- Types ---
type Platform = 'xiaohongshu' | 'instagram' | 'facebook';

interface GeneratedContent {
  title: string;
  body: string;
  hashtags: string[];
}

interface AppState {
  originalImage: string | null;
  enhancedImages: string[];
  content: Record<Platform, GeneratedContent | null>;
  isGenerating: boolean;
  activePlatform: Platform;
}

const PLATFORM_CONFIG = {
  xiaohongshu: { name: '小红书', color: 'bg-[#FF2442]', icon: '✨' },
  instagram: { name: 'Instagram', color: 'bg-gradient-to-tr from-[#F58529] via-[#DD2A7B] to-[#8134AF]', icon: '📸' },
  facebook: { name: 'Facebook', color: 'bg-[#1877F2]', icon: '👥' }
};

const App = () => {
  const [state, setState] = useState<AppState>({
    originalImage: null,
    enhancedImages: [],
    content: { xiaohongshu: null, instagram: null, facebook: null },
    isGenerating: false,
    activePlatform: 'xiaohongshu',
  });
  const [productDesc, setProductDesc] = useState('');
  const [copied, setCopied] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setState(prev => ({ ...prev, originalImage: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const generateAI = async () => {
    if (!state.originalImage || !productDesc) return;
    setState(prev => ({ ...prev, isGenerating: true }));

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    const base64Data = state.originalImage.split(',')[1];

    try {
      // 1. 生成增强后的图片 (串行或并行生成多张，这里为了速度先生成两张风格化版本)
      const imagePrompts = [
        "Enhance this product image for social media. Make it look professional, bright, and premium. High resolution, aesthetic background.",
        "Create a stylized lifestyle version of this product. Soft morning lighting, natural aesthetic, perfect for Instagram grid."
      ];

      const imagePromises = imagePrompts.map(prompt => 
        ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: {
            parts: [
              { inlineData: { data: base64Data, mimeType: 'image/png' } },
              { text: prompt }
            ]
          }
        })
      );

      // 2. 生成多平台文案
      const textPrompt = `
        Product: ${productDesc}
        Please generate marketing content for 3 platforms:
        1. Xiaohongshu (XHS): Viral title with emojis, bullet point body text, high-engagement tags.
        2. Instagram: Aesthetic, brief, storytelling style, emoji-rich, hashtags.
        3. Facebook: Detailed, community-focused, clear CTA, professional but friendly.

        Output MUST be in JSON format:
        {
          "xiaohongshu": { "title": "", "body": "", "hashtags": [] },
          "instagram": { "title": "", "body": "", "hashtags": [] },
          "facebook": { "title": "", "body": "", "hashtags": [] }
        }
      `;

      const textPromise = ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: textPrompt,
        config: { responseMimeType: 'application/json' }
      });

      const [imgRes1, imgRes2, textRes] = await Promise.all([...imagePromises, textPromise]);

      // 提取图片
      const newImages: string[] = [];
      [imgRes1, imgRes2].forEach(res => {
        const part = res.candidates?.[0]?.content?.parts.find(p => p.inlineData);
        if (part?.inlineData) newImages.push(`data:image/png;base64,${part.inlineData.data}`);
      });

      // 提取文案
      const content = JSON.parse(textRes.text);

      setState(prev => ({
        ...prev,
        enhancedImages: newImages,
        content,
        isGenerating: false
      }));

    } catch (err) {
      console.error("AI Generation Error:", err);
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const copyToClipboard = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopied(id);
    setTimeout(() => setCopied(null), 2000);
  };

  return (
    <div className="min-h-screen bg-[#050505] text-slate-100 font-sans selection:bg-violet-500/30">
      {/* Header */}
