              <h2 className="font-bold text-lg">产品编辑台</h2>
            </div>

            {/* Image Upload Area */}
            <div 
              onClick={() => fileInputRef.current?.click()}
              className={`relative border-2 border-dashed rounded-2xl transition-all cursor-pointer group overflow-hidden ${state.originalImage ? 'border-violet-500/50' : 'border-white/10 hover:border-white/20 h-48 flex flex-col items-center justify-center'}`}
            >
              <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*" />
              {state.originalImage ? (
                <div className="relative group">
                  <img src={state.originalImage} alt="Product" className="w-full h-64 object-cover rounded-xl" />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                    <RefreshCw className="text-white" />
                  </div>
                </div>
              ) : (
                <>
                  <div className="bg-white/5 p-4 rounded-full mb-3 group-hover:scale-110 transition-transform">
                    <Upload size={24} className="text-slate-400" />
                  </div>
                  <p className="text-sm font-medium text-slate-400">点击或拖拽上传产品照片</p>
                  <p className="text-[10px] text-slate-600 mt-1 uppercase">Supports JPG, PNG, WEBP</p>
                </>
              )}
            </div>

            {/* Product Description */}
