import React, { useState, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { 
  Sparkles, 
  Image as ImageIcon, 
  Upload, 
  Copy, 
  Check, 
  Loader2, 
  RefreshCw, 
  ShoppingBag, 
  Zap,
  Palette,
  Settings2
} from 'lucide-react';
import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

// --- Types ---
type Platform = 'xiaohongshu' | 'instagram' | 'facebook';

interface GeneratedContent {
  title: string;
  body: string;
  hashtags: string[];
}

interface AppState {
  originalImage: string | null;
  enhancedImages: string[];
  content: Record<Platform, GeneratedContent | null>;
  isGenerating: boolean;
  activePlatform: Platform;
  stylePreference: string;
  isCustomizable: boolean;
}

const PLATFORM_CONFIG = {
  xiaohongshu: { name: '小红书', color: 'bg-[#FF2442]', icon: '✨' },
  instagram: { name: 'Instagram', color: 'bg-gradient-to-tr from-[#F58529] via-[#DD2A7B] to-[#8134AF]', icon: '📸' },
  facebook: { name: 'Facebook', color: 'bg-[#1877F2]', icon: '👥' }
};

const App = () => {
  const [state, setState] = useState<AppState>({
    originalImage: null,
    enhancedImages: [],
    content: { xiaohongshu: null, instagram: null, facebook: null },
    isGenerating: false,
    activePlatform: 'xiaohongshu',
    stylePreference: '',
    isCustomizable: false,
  });
  const [productDesc, setProductDesc] = useState('');
  const [copied, setCopied] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setState(prev => ({ ...prev, originalImage: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const generateAI = async () => {
    if (!state.originalImage || !productDesc) return;
    setState(prev => ({ ...prev, isGenerating: true }));

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const base64Data = state.originalImage.split(',')[1];

    try {
      // 1. 生成增强后的图片
      const styleContext = state.stylePreference ? `Follow this style preference: ${state.stylePreference}.` : "Make it look professional and aesthetic.";
      const imagePrompts = [
        `Enhance this product image for social media. ${styleContext} High resolution, premium look, clean background.`,
        `Create a stylized lifestyle version of this product. ${styleContext} Soft lighting, natural aesthetic, perfect for a feed.`
      ];

      const imagePromises = imagePrompts.map(prompt => 
        ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: {
            parts: [
              { inlineData: { data: base64Data, mimeType: 'image/png' } },
              { text: prompt }
            ]
          }
        })
      );

      // 2. 生成多平台文案
      const customText = state.isCustomizable ? "Note: This product is customizable (可定制)." : "";
      const textPrompt = `
        Product: ${productDesc}
        Style Preference: ${state.stylePreference || "Modern & Professional"}
        ${customText}

        Please generate marketing content for 3 platforms:
        1. Xiaohongshu (XHS): Viral title with emojis, emotional hooks, bullet point body text, high-engagement tags.
        2. Instagram: Aesthetic, brief storytelling, emoji-rich, specific hashtags.
        3. Facebook: Informative, community-focused, clear CTA, professional but friendly.

        Output MUST be in JSON format:
        {
          "xiaohongshu": { "title": "", "body": "", "hashtags": [] },
          "instagram": { "title": "", "body": "", "hashtags": [] },
          "facebook": { "title": "", "body": "", "hashtags": [] }
        }
      `;

      const textPromise = ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: textPrompt,
        config: { responseMimeType: 'application/json' }
      });

      const results = (await Promise.all([...imagePromises, textPromise])) as GenerateContentResponse[];
      const [imgRes1, imgRes2, textRes] = results;

      const newImages: string[] = [];
      [imgRes1, imgRes2].forEach(res => {
        const part = res.candidates?.[0]?.content?.parts.find(p => p.inlineData);
        if (part?.inlineData) newImages.push(`data:image/png;base64,${part.inlineData.data}`);
      });

      const jsonText = textRes.text;
      if (!jsonText) throw new Error("No content returned");
      const content = JSON.parse(jsonText);

      setState(prev => ({
        ...prev,
        enhancedImages: newImages,
        content,
        isGenerating: false
      }));

    } catch (err) {
      console.error("AI Generation Error:", err);
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const copyToClipboard = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopied(id);
    setTimeout(() => setCopied(null), 2000);
  };

  return (
    <div className="min-h-screen bg-[#050505] text-slate-100 font-sans selection:bg-violet-500/30">
      <nav className="h-16 border-b border-white/5 bg-black/40 backdrop-blur-md flex items-center justify-between px-6 sticky top-0 z-50">
        <div className="flex items-center gap-3">
          <div className="bg-violet-600 p-2 rounded-xl shadow-lg shadow-violet-600/20">
            <ShoppingBag size={20} className="text-white" />
          </div>
          <h1 className="text-lg font-bold tracking-tight">Creator<span className="text-violet-500">Master</span></h1>
        </div>
        <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-emerald-500/10 border border-emerald-500/20">
          <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
          <span className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest">AI Agent Ready</span>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto p-6 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* LEFT: Input Section */}
        <div className="lg:col-span-5 space-y-6">
          <section className="bg-white/5 border border-white/10 rounded-3xl p-6 space-y-6 shadow-2xl">
            <div className="flex items-center gap-2 mb-2">
              <Zap size={18} className="text-violet-400" />
              <h2 className="font-bold text-lg">产品编辑台</h2>
            </div>

            {/* Image Upload Area */}
            <div 
              onClick={() => fileInputRef.current?.click()}
              className={`relative border-2 border-dashed rounded-2xl transition-all cursor-pointer group overflow-hidden ${state.originalImage ? 'border-violet-500/50' : 'border-white/10 hover:border-white/20 h-48 flex flex-col items-center justify-center'}`}
            >
              <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*" />
              {state.originalImage ? (
                <div className="relative group">
                  <img src={state.originalImage} alt="Product" className="w-full h-64 object-cover rounded-xl" />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                    <RefreshCw className="text-white" />
                  </div>
                </div>
              ) : (
                <>
                  <div className="bg-white/5 p-4 rounded-full mb-3 group-hover:scale-110 transition-transform">
                    <Upload size={24} className="text-slate-400" />
                  </div>
                  <p className="text-sm font-medium text-slate-400">点击或拖拽上传产品照片</p>
                  <p className="text-[10px] text-slate-600 mt-1 uppercase">Supports JPG, PNG, WEBP</p>
                </>
              )}
            </div>

            {/* Product Description */}
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">产品描述</label>
              <textarea 
                rows={3}
                value={productDesc}
                onChange={(e) => setProductDesc(e.target.value)}
                placeholder="例如：纯手工制作的薰衣草香薰蜡烛，采用大豆蜡..."
                className="w-full bg-black/40 border border-white/10 rounded-2xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-violet-500/50 transition-all placeholder:text-slate-700 resize-none"
              />
            </div>

            {/* Platform Selection (Moved Here) */}
            <div className="space-y-3">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">发布平台</label>
              <div className="flex bg-black/40 p-1 rounded-2xl border border-white/10">
                {(['xiaohongshu', 'instagram', 'facebook'] as Platform[]).map((p) => (
                  <button
                    key={p}
                    onClick={() => setState(prev => ({ ...prev, activePlatform: p }))}
                    className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl text-xs font-bold transition-all ${
                      state.activePlatform === p 
                        ? 'bg-violet-600 text-white shadow-lg' 
                        : 'text-slate-500 hover:text-slate-300'
                    }`}
                  >
                    <span>{PLATFORM_CONFIG[p].icon}</span>
                    {PLATFORM_CONFIG[p].name}
                  </button>
                ))}
              </div>
            </div>

            {/* Style Preference */}
            <div className="space-y-2">
              <div className="flex items-center gap-2 text-slate-500">
                <Palette size={14} />
                <label className="text-xs font-bold uppercase tracking-widest">风格偏好</label>
              </div>
              <input 
                type="text"
                value={state.stylePreference}
                onChange={(e) => setState(prev => ({ ...prev, stylePreference: e.target.value }))}
                placeholder="例如：温馨家居风、极简工业风、清新日系..."
                className="w-full bg-black/40 border border-white/10 rounded-2xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-violet-500/50 transition-all placeholder:text-slate-700"
              />
            </div>

            {/* Customizable Toggle */}
            <div className="flex items-center justify-between p-4 bg-black/40 border border-white/10 rounded-2xl group cursor-pointer" onClick={() => setState(prev => ({ ...prev, isCustomizable: !prev.isCustomizable }))}>
              <div className="flex items-center gap-2">
                <Settings2 size={16} className="text-violet-400" />
                <span className="text-sm font-medium">是否支持定制产品</span>
              </div>
              <div className={`w-10 h-6 rounded-full transition-colors relative ${state.isCustomizable ? 'bg-violet-600' : 'bg-slate-700'}`}>
                <div className={`absolute top-1 left-1 w-4 h-4 bg-white rounded-full transition-transform ${state.isCustomizable ? 'translate-x-4' : ''}`}></div>
              </div>
            </div>

            <button 
              onClick={generateAI}
              disabled={state.isGenerating || !state.originalImage || !productDesc}
              className={`w-full py-4 rounded-2xl font-bold text-lg flex items-center justify-center gap-2 transition-all shadow-xl ${
                state.isGenerating 
                  ? 'bg-slate-800 text-slate-500 cursor-not-allowed' 
                  : 'bg-violet-600 hover:bg-violet-500 text-white shadow-violet-600/20 active:scale-[0.98]'
              }`}
            >
              {state.isGenerating ? (
                <>
                  <Loader2 className="animate-spin" size={20} />
                  AI 正在创作中...
                </>
              ) : (
                <>
                  <Sparkles size={20} className="fill-current" />
                  生成优化内容
                </>
              )}
            </button>
          </section>
        </div>

        {/* RIGHT: Output Section */}
        <div className="lg:col-span-7 space-y-6">
          {!state.content[state.activePlatform] && !state.isGenerating ? (
