                      <h3 className="font-bold text-slate-800">{PLATFORM_CONFIG[state.activePlatform].name[state.lang]}</h3>
                      <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">Optimized Strategy</p>
                    </div>
                  </div>
                  <button 
                    onClick={() => copyToClipboard(`${state.content[state.activePlatform]?.title}\n\n${state.content[state.activePlatform]?.body}`, 'all')}
                    className="flex items-center gap-2 px-4 py-2 bg-slate-100 hover:bg-slate-200 rounded-xl transition-colors text-slate-600 text-xs font-bold shadow-sm"
                  >
                    {copied === 'all' ? <Check size={14} className="text-emerald-600" /> : <Copy size={14} />}
                    {t.copyBtn}
                  </button>
                </div>

                <div className="space-y-5">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">{t.suggestedTitle}</label>
                    <div className="p-4 bg-slate-50 border border-slate-100 rounded-2xl text-lg font-bold text-slate-800 relative">
                      {state.content[state.activePlatform]?.title}
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">{t.bodyText}</label>
                    <div className="p-4 bg-slate-50 border border-slate-100 rounded-2xl text-sm leading-relaxed text-slate-600 whitespace-pre-wrap min-h-[120px]">
                      {state.content[state.activePlatform]?.body}
                    </div>
                  </div>

                  <div className="flex flex-wrap gap-2 pt-2">
                    {state.content[state.activePlatform]?.hashtags.map((tag, i) => (
                      <span key={i} className="px-3 py-1 bg-blue-50 border border-blue-100 rounded-full text-[10px] font-bold text-blue-600 uppercase">
                        #{tag}
                      </span>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="h-14 flex items-center justify-center border-t border-slate-200 mt-12 bg-white text-[10px] font-bold text-slate-400 uppercase tracking-widest">
        {t.footer}
      </footer>
    </div>
  );
};

const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(<App />);
}

{
