                  </div>
                  {productDesc && (
                    <button 
                      onClick={suggestHashtags}
                      disabled={state.isGeneratingHashtags}
                      className="text-[10px] font-bold text-blue-500 hover:text-blue-700 flex items-center gap-1 transition-colors uppercase disabled:opacity-50"
                    >
                      {state.potentialHashtags.length > 0 ? (
                        <><RotateCcw size={12} /> {t.regenerate}</>
                      ) : (
                        <><Sparkles size={12} /> {t.suggestTags}</>
                      )}
                    </button>
                  )}
                </div>
                <p className="text-[10px] text-slate-500 leading-tight mb-3">
                  {t.focusHelper}
                </p>

                <div className="flex flex-wrap gap-2 min-h-[32px] items-center">
                  {state.isGeneratingHashtags ? (
                    <div className="flex items-center gap-2 text-[10px] text-blue-400 font-bold animate-pulse">
                      <Loader2 size={12} className="animate-spin" />
                      ANALYZING DESCRIPTION...
                    </div>
                  ) : state.potentialHashtags.length > 0 ? (
                    state.potentialHashtags.map((tag, i) => (
                      <span key={i} className="px-3 py-1 bg-white border border-blue-200 rounded-full text-[10px] font-bold text-blue-600 shadow-sm animate-in fade-in zoom-in duration-300">
                        {tag.startsWith('#') ? tag : `#${tag}`}
                      </span>
                    ))
                  ) : (
                    <div className="text-[10px] text-slate-300 font-medium italic">
                      {state.lang === 'zh' ? '暂无标签，请输入描述后生成' : 'No tags yet, type description to suggest'}
                    </div>
                  )}
                </div>
              </div>

              <div className="space-y-2">
                <div className="flex items-center gap-2 text-slate-500">
                  <Settings2 size={14} />
                  <label className="text-[10px] font-bold uppercase tracking-widest">{t.isCustom}</label>
                </div>
                <button 
                  onClick={() => setState(prev => ({ ...prev, isCustomizable: !prev.isCustomizable }))}
                  className={`w-full flex items-center justify-between px-4 py-2 rounded-xl border transition-all text-sm font-medium ${state.isCustomizable ? 'bg-blue-50 border-blue-200 text-blue-700' : 'bg-slate-50 border-slate-200 text-slate-500'}`}
                >
                  {state.isCustomizable ? (state.lang === 'zh' ? '已开启' : 'ON') : (state.lang === 'zh' ? '已关闭' : 'OFF')}
                  <div className={`w-8 h-4 rounded-full relative transition-colors ${state.isCustomizable ? 'bg-blue-500' : 'bg-slate-300'}`}>
                    <div className={`absolute top-0.5 left-0.5 w-3 h-3 bg-white rounded-full transition-transform ${state.isCustomizable ? 'translate-x-4' : ''}`} />
                  </div>
                </button>
              </div>
            </div>

            <button 
              onClick={generateAI}
              disabled={state.isGenerating || !state.originalImage || !productDesc}
              className={`w-full py-4 rounded-2xl font-bold text-lg flex items-center justify-center gap-2 transition-all shadow-lg ${
                state.isGenerating 
                  ? 'bg-slate-100 text-slate-400 cursor-not-allowed border border-slate-200' 
                  : 'bg-blue-600 hover:bg-blue-700 text-white shadow-blue-600/20 active:scale-[0.98]'
              }`}
            >
              {state.isGenerating ? (
                <>
                  <Loader2 className="animate-spin" size={20} />
                  {t.generating}
                </>
              ) : (
                <>
                  <Sparkles size={20} className="fill-current" />
                  {t.generateBtn}
                </>
              )}
            </button>
          </section>
        </div>

        {/* RIGHT: Output Section */}
        <div className="lg:col-span-7 space-y-6">
          {!state.content[state.activePlatform] && !state.isGenerating ? (
            <div className="h-full min-h-[500px] bg-white border border-slate-200 rounded-3xl flex flex-col items-center justify-center text-center p-8 transition-all hover:bg-slate-50/50">
              <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mb-6 border border-slate-100 shadow-inner">
                <ImageIcon size={32} className="text-slate-300" />
              </div>
              <h3 className="text-xl font-bold mb-2 text-slate-800 tracking-tight">{t.outputTitle}</h3>
              <p className="max-w-xs text-sm text-slate-400 leading-relaxed font-medium">{t.outputSub}</p>
            </div>
          ) : state.isGenerating ? (
            <div className="h-full min-h-[500px] bg-white border border-slate-200 rounded-3xl flex flex-col items-center justify-center p-8 shadow-sm">
              <div className="relative mb-8">
                <div className="w-24 h-24 border-b-2 border-blue-500 rounded-full animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center">
                  <RefreshCw className="text-blue-500 animate-pulse" size={24} />
                </div>
              </div>
              <h3 className="text-xl font-bold text-slate-800 animate-pulse">{t.rendering}</h3>
              <p className="text-slate-400 text-xs mt-2 font-bold uppercase tracking-widest">Optimizing visuals and copy...</p>
            </div>
          ) : (
            <div className="space-y-6 animate-in fade-in slide-in-from-right duration-700">
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                    <ImageIcon size={14} />
                    {t.enhancedImg}
                  </h3>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  {state.enhancedImages.map((img, i) => (
                    <div key={i} className="group relative rounded-2xl overflow-hidden aspect-[4/5] border border-slate-100 shadow-sm bg-white hover:shadow-lg transition-all duration-300">
                      <img src={img} alt={`Enhanced ${i}`} className="w-full h-full object-cover transition-transform group-hover:scale-105" />
                      <button 
                        onClick={() => {
                          const link = document.createElement('a');
                          link.href = img;
                          link.download = `creatorplus-${i}.png`;
                          link.click();
                        }}
                        className="absolute bottom-3 right-3 p-2 bg-white/90 backdrop-blur shadow-lg rounded-lg text-slate-700 opacity-0 group-hover:opacity-100 transition-all duration-300 hover:bg-blue-600 hover:text-white transform group-hover:translate-y-0 translate-y-2"
                      >
                        <Download size={14} />
                      </button>
                    </div>
                  ))}
                </div>
              </div>

              <div className="bg-white border border-slate-200 rounded-3xl p-6 space-y-6 shadow-sm hover:shadow-md transition-shadow">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className={`w-10 h-10 ${PLATFORM_CONFIG[state.activePlatform].color} rounded-xl flex items-center justify-center text-lg shadow-md transition-transform hover:scale-110`}>
                      {PLATFORM_CONFIG[state.activePlatform].icon}
                    </div>
                    <div>
                      <h3 className="font-bold text-slate-800">{PLATFORM_CONFIG[state.activePlatform].name[state.lang]}</h3>
                      <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">AI Content Engine</p>
                    </div>
                  </div>
                  <button 
                    onClick={() => copyToClipboard(`${state.content[state.activePlatform]?.title}\n\n${state.content[state.activePlatform]?.body}`, 'all')}
                    className="flex items-center gap-2 px-4 py-2 bg-slate-100 hover:bg-slate-200 rounded-xl transition-all text-slate-600 text-xs font-bold shadow-sm active:scale-95"
                  >
                    {copied === 'all' ? <Check size={14} className="text-emerald-600" /> : <Copy size={14} />}
                    {t.copyBtn}
                  </button>
                </div>

                <div className="space-y-5">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">{t.suggestedTitle}</label>
                    <div className="p-4 bg-slate-50 border border-slate-100 rounded-2xl text-lg font-extrabold text-slate-800 relative shadow-inner">
                      {state.content[state.activePlatform]?.title}
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">{t.bodyText}</label>
                    <div className="p-4 bg-slate-50 border border-slate-100 rounded-2xl text-sm leading-relaxed text-slate-600 whitespace-pre-wrap min-h-[140px] shadow-inner font-medium">
                      {state.content[state.activePlatform]?.body}
                    </div>
                  </div>

                  <div className="flex flex-wrap gap-2 pt-2">
                    {state.content[state.activePlatform]?.hashtags.map((tag, i) => (
                      <span key={i} className="px-3 py-1 bg-blue-50 border border-blue-100 rounded-full text-[10px] font-bold text-blue-600 uppercase shadow-sm transition-transform hover:scale-105 cursor-default">
                        #{tag}
                      </span>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="h-16 flex items-center justify-center border-t border-slate-200 mt-12 bg-white text-[10px] font-bold text-slate-400 uppercase tracking-widest">
        {t.footer}
      </footer>

      <style>{`
        .animate-spin-slow {
          animation: spin 3s linear infinite;
        }
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
};

const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(<App />);
}

