import React, { useState, useRef, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { 
  Sparkles, 
  Image as ImageIcon, 
  Upload, 
  Copy, 
  Check, 
  Loader2, 
  RefreshCw, 
  ShoppingBag, 
  Zap,
  Palette,
  Settings2,
  Globe,
  Download,
  Hash,
  RotateCcw,
  Wand2
} from 'lucide-react';
import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

// --- Types & Config ---
type Platform = 'xiaohongshu' | 'instagram' | 'facebook';
type Language = 'zh' | 'en';

interface GeneratedContent {
  title: string;
  body: string;
  hashtags: string[];
}

interface AppState {
  originalImage: string | null;
  enhancedImages: string[];
  content: Record<Platform, GeneratedContent | null>;
  isGenerating: boolean;
  activePlatform: Platform;
  stylePreference: string;
  isCustomizable: boolean;
  lang: Language;
  potentialHashtags: string[];
  isGeneratingHashtags: boolean;
  isAnalyzingImage: boolean;
}

const PLATFORM_CONFIG = {
  xiaohongshu: { name: { zh: '小红书', en: 'Xiaohongshu' }, color: 'bg-[#FF2442]', icon: '✨' },
  instagram: { name: { zh: 'Instagram', en: 'Instagram' }, color: 'bg-gradient-to-tr from-[#F58529] via-[#DD2A7B] to-[#8134AF]', icon: '📸' },
  facebook: { name: { zh: 'Facebook', en: 'Facebook' }, color: 'bg-[#1877F2]', icon: '👥' }
};

const TRANSLATIONS = {
  zh: {
    brand: 'CreatorPlus',
    agentReady: 'AI 引擎就绪',
    editorStudio: '产品编辑台',
    uploadPrompt: '点击或拖拽上传产品照片',
    uploadSub: '支持 JPG, PNG, WEBP',
    productDesc: '产品描述',
    productPlaceholder: '例如：纯手工制作的薰衣草香薰蜡烛，采用大豆蜡...',
    publishPlatform: '发布平台',
    stylePref: '风格偏好',
    stylePlaceholder: '例如：温馨家居风、极简工业风...',
    potentialHashtags: '潜在核心标签 (Potential Hashtags)',
    focusHelper: '基于您的作品和平台，这是人们最容易注意到的点',
    suggestTags: '点击生成标签',
    regenerate: '换一批',
    isCustom: '支持定制产品',
    generateBtn: '生成全套内容',
    generating: 'AI 正在创作中...',
    outputTitle: '生成结果',
    outputSub: '点击左侧生成按钮开启您的创作之旅。',
    rendering: '正在渲染...',
    enhancedImg: 'AI 优化图片推荐',
    copyBtn: '一键复制',
    suggestedTitle: '建议标题',
    bodyText: '内容正文',
    footer: 'CreatorPlus v3.2 • 由 Gemini AI Studio 提供支持',
    analyzingImage: '正在通过 AI 分析图片...'
  },
  en: {
    brand: 'CreatorPlus',
    agentReady: 'AI Agent Ready',
    editorStudio: 'Editor Studio',
    uploadPrompt: 'Click or drag to upload photo',
    uploadSub: 'Supports JPG, PNG, WEBP',
    productDesc: 'Product Description',
    productPlaceholder: 'e.g. Handmade lavender scented candle using soy wax...',
    publishPlatform: 'Publish Platform',
    stylePref: 'Style Preference',
    stylePlaceholder: 'e.g. Warm home style, Minimalist, Cinematic...',
    potentialHashtags: 'Potential Hashtags',
    focusHelper: 'Based on your work and platform, here’s what people are most likely to notice',
    suggestTags: 'Suggest Tags',
    regenerate: 'Refresh',
    isCustom: 'Customizable Product',
    generateBtn: 'Generate Content',
    generating: 'AI is working...',
    outputTitle: 'Generated Results',
    outputSub: 'Upload and describe your product to start.',
    rendering: 'Rendering...',
    enhancedImg: 'AI Enhanced Images',
    copyBtn: 'Copy Content',
    suggestedTitle: 'Suggested Title',
    bodyText: 'Body Content',
    footer: 'CreatorPlus v3.2 • Powered by Gemini AI Studio',
    analyzingImage: 'AI is analyzing your image...'
  }
};

const App = () => {
  const [state, setState] = useState<AppState>({
    originalImage: null,
    enhancedImages: [],
    content: { xiaohongshu: null, instagram: null, facebook: null },
    isGenerating: false,
    activePlatform: 'xiaohongshu',
    stylePreference: '',
    isCustomizable: false,
    lang: 'zh',
    potentialHashtags: [],
    isGeneratingHashtags: false,
    isAnalyzingImage: false,
  });
  const [productDesc, setProductDesc] = useState('');
  const [copied, setCopied] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const t = TRANSLATIONS[state.lang];

  // Auto-generate description when image is uploaded and description is empty
  useEffect(() => {
    const triggerAutoDescription = async () => {
      if (state.originalImage && !productDesc && !state.isAnalyzingImage) {
        setState(prev => ({ ...prev, isAnalyzingImage: true }));
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const base64Data = state.originalImage.split(',')[1];

        try {
          const visionPrompt = state.lang === 'zh' 
            ? "请用一句话描述这张产品图的核心卖点，适合小红书推广"
            : "Please describe the core selling point of this product in one concise sentence, suitable for social media promotion.";

          const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: {
              parts: [
                { inlineData: { data: base64Data, mimeType: 'image/png' } },
                { text: visionPrompt }
              ]
            }
          });

          if (response.text) {
            setProductDesc(response.text.trim());
          }
        } catch (err) {
          console.error("Auto-description error:", err);
        } finally {
          setState(prev => ({ ...prev, isAnalyzingImage: false }));
        }
      }
    };

    triggerAutoDescription();
  }, [state.originalImage]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setState(prev => ({ ...prev, originalImage: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const suggestHashtags = async () => {
    if (!productDesc) return;
    setState(prev => ({ ...prev, isGeneratingHashtags: true }));
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      const prompt = `Based on this product description: "${productDesc}", extract 1 to 3 highly relevant and catchy hashtags in ${state.lang === 'zh' ? 'Chinese' : 'English'}. Return ONLY a JSON array of strings. Example: ["#Handmade", "#EcoFriendly"]`;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: 'application/json' }
      });

      const tags = JSON.parse(response.text || '[]');
      setState(prev => ({ ...prev, potentialHashtags: tags, isGeneratingHashtags: false }));
    } catch (err) {
      console.error(err);
      setState(prev => ({ ...prev, isGeneratingHashtags: false }));
    }
  };

  const generateAI = async () => {
    if (!state.originalImage || !productDesc) return;
    setState(prev => ({ ...prev, isGenerating: true }));

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const base64Data = state.originalImage.split(',')[1];

    try {
      const styleContext = state.stylePreference ? `Follow style: ${state.stylePreference}.` : "Make it look professional and aesthetic.";
      const keywordContext = state.potentialHashtags.length > 0 ? `Incorporate these focus keywords/themes: ${state.potentialHashtags.join(', ')}.` : "";

      const imagePrompts = [
        `Enhance this product image for social media. ${styleContext} ${keywordContext} High resolution, premium look.`,
        `Create a stylized lifestyle version of this product. ${styleContext} ${keywordContext} Perfect for social media feed.`
      ];

      const imagePromises = imagePrompts.map(prompt => 
        ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: {
            parts: [
              { inlineData: { data: base64Data, mimeType: 'image/png' } },
              { text: prompt }
            ]
          }
        })
      );

      const customText = state.isCustomizable ? "Note: This product is customizable." : "";
      const textPrompt = `
        Language: ${state.lang === 'zh' ? 'Chinese' : 'English'}
        Product: ${productDesc}
        Style Preference: ${state.stylePreference || "Modern"}
        Focus Tags: ${state.potentialHashtags.join(', ') || "None specified"}
        ${customText}

        Generate content for Xiaohongshu (viral/emoji), Instagram (aesthetic/brief), and Facebook (informative/CTA).
        Generate content in ${state.lang === 'zh' ? 'Chinese' : 'English'}.
        Ensure the copy highlights the focus tags/themes if provided.

        Output MUST be in JSON format:
        {
          "xiaohongshu": { "title": "", "body": "", "hashtags": [] },
          "instagram": { "title": "", "body": "", "hashtags": [] },
          "facebook": { "title": "", "body": "", "hashtags": [] }
        }
      `;

      const textPromise = ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: textPrompt,
        config: { responseMimeType: 'application/json' }
      });

      const results = (await Promise.all([...imagePromises, textPromise])) as GenerateContentResponse[];
      const [imgRes1, imgRes2, textRes] = results;

      const newImages: string[] = [];
      [imgRes1, imgRes2].forEach(res => {
        const part = res.candidates?.[0]?.content?.parts.find(p => p.inlineData);
        if (part?.inlineData) newImages.push(`data:image/png;base64,${part.inlineData.data}`);
      });

      const jsonText = textRes.text;
      if (!jsonText) throw new Error("No content");
      const content = JSON.parse(jsonText);

      setState(prev => ({
        ...prev,
        enhancedImages: newImages,
        content,
        isGenerating: false
      }));

    } catch (err) {
      console.error(err);
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const copyToClipboard = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopied(id);
    setTimeout(() => setCopied(null), 2000);
  };

  const toggleLang = () => {
    setState(prev => ({ ...prev, lang: prev.lang === 'zh' ? 'en' : 'zh' }));
  };

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans selection:bg-blue-100">
      {/* Header */}
      <nav className="h-16 border-b border-slate-200 bg-white/80 backdrop-blur-md flex items-center justify-between px-6 sticky top-0 z-50">
        <div className="flex items-center gap-3">
          <div className="bg-blue-600 p-2 rounded-xl shadow-lg shadow-blue-600/20 transition-transform hover:scale-105 active:scale-95">
            <ShoppingBag size={20} className="text-white" />
          </div>
          <h1 className="text-xl font-extrabold tracking-tight text-slate-900">{t.brand}</h1>
        </div>

        <div className="flex items-center gap-4">
          <div className="hidden md:flex items-center gap-2 px-3 py-1.5 rounded-full bg-emerald-50 border border-emerald-200">
            <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
            <span className="text-[10px] font-bold text-emerald-700 uppercase tracking-widest">{t.agentReady}</span>
          </div>

          <button 
            onClick={toggleLang}
            className="flex items-center gap-2 px-3 py-1.5 rounded-lg border border-slate-200 hover:bg-slate-50 transition-all text-xs font-bold text-slate-600 shadow-sm active:scale-95"
          >
            <Globe size={14} />
            {state.lang === 'zh' ? 'English' : '中文'}
          </button>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto p-6 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* LEFT: Input Section */}
        <div className="lg:col-span-5 space-y-6">
