                    </div>
                    <div>
                      <h3 className="font-bold text-slate-800 tracking-tight">{PLATFORM_CONFIG[state.activePlatform].name[state.lang]}</h3>
                      <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">AI Content Engine</p>
                    </div>
                  </div>
                  <button 
                    onClick={() => copyToClipboard(`${state.content[state.activePlatform]?.title}\n\n${state.content[state.activePlatform]?.body}`, 'all')}
                    className="flex items-center gap-2 px-4 py-2 bg-slate-100 hover:bg-slate-200 rounded-xl transition-all text-slate-600 text-xs font-black shadow-sm active:scale-95 border border-slate-200/50"
                  >
                    {copied === 'all' ? <Check size={14} className="text-emerald-600" /> : <Copy size={14} />}
                    {t.copyBtn}
                  </button>
                </div>

                <div className="space-y-5">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">{t.suggestedTitle}</label>
                    <div className="p-5 bg-slate-50 border border-slate-100 rounded-2xl text-lg font-extrabold text-slate-800 relative shadow-inner tracking-tight">
                      {state.content[state.activePlatform]?.title}
                    </div>
