                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">{t.bodyText}</label>
                    <div className="p-5 bg-slate-50 border border-slate-100 rounded-2xl text-sm leading-relaxed text-slate-600 whitespace-pre-wrap min-h-[140px] shadow-inner font-semibold">
                      {state.content[state.activePlatform]?.body}
                    </div>
                  </div>

                  <div className="flex flex-wrap gap-2 pt-2">
                    {state.content[state.activePlatform]?.hashtags.map((tag, i) => (
                      <span key={i} className="px-3 py-1 bg-blue-50 border border-blue-100 rounded-full text-[10px] font-black text-blue-600 uppercase shadow-sm transition-transform hover:scale-105 cursor-default tracking-wide">
                        #{tag}
                      </span>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="h-16 flex items-center justify-center border-t border-slate-200 mt-12 bg-white text-[10px] font-black text-slate-400 uppercase tracking-widest">
        {t.footer}
      </footer>

      <style>{`
        .animate-spin-slow {
          animation: spin 3s linear infinite;
        }
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
};

const container = document.getElementById('root');
