              {/* Potential Hashtags Section */}
              <div className="space-y-2 p-4 bg-blue-50/50 border border-blue-100/50 rounded-2xl transition-all hover:bg-blue-50">
                <div className="flex items-center justify-between text-blue-600 mb-1">
