import React, { useState, useRef, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { 
  Sparkles, 
  Image as ImageIcon, 
  Upload, 
  Copy, 
  Check, 
  Loader2, 
  RefreshCw, 
  ShoppingBag, 
  Zap,
  Palette,
  Settings2,
  Globe,
  Download,
  Hash,
  RotateCcw,
  Wand2,
  Cloud,
  X,
  Mail,
  ArrowRight,
  User as UserIcon,
  LogOut,
  History,
  ChevronDown,
  Clock,
  ExternalLink
} from 'lucide-react';
import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

// --- Types & Config ---
type Platform = 'xiaohongshu' | 'instagram' | 'facebook';
type Language = 'zh' | 'en';

interface GeneratedContent {
  title: string;
  body: string;
  hashtags: string[];
}

interface HistoryItem {
  id: string;
  image: string;
  desc: string;
  platform: Platform;
  content: GeneratedContent;
  timestamp: number;
}

interface User {
  email: string;
}

interface AppState {
  originalImage: string | null;
  enhancedImages: string[];
  content: Record<Platform, GeneratedContent | null>;
  isGenerating: boolean;
  activePlatform: Platform;
  stylePreference: string;
  isCustomizable: boolean;
  lang: Language;
  potentialHashtags: string[];
  isGeneratingHashtags: boolean;
  isAnalyzingImage: boolean;
  generationCount: number;
  showSyncModal: boolean;
  user: User | null;
  history: HistoryItem[];
  isHistoryOpen: boolean;
}

const PLATFORM_CONFIG = {
  xiaohongshu: { name: { zh: '小红书', en: 'Xiaohongshu' }, color: 'bg-[#FF2442]', icon: '✨' },
  instagram: { name: { zh: 'Instagram', en: 'Instagram' }, color: 'bg-gradient-to-tr from-[#F58529] via-[#DD2A7B] to-[#8134AF]', icon: '📸' },
  facebook: { name: { zh: 'Facebook', en: 'Facebook' }, color: 'bg-[#1877F2]', icon: '👥' }
};

