    productDesc: 'Product Description',
    productPlaceholder: 'e.g. Handmade lavender scented candle using soy wax...',
    publishPlatform: 'Publish Platform',
    stylePref: 'Style Preference',
    stylePlaceholder: 'e.g. Warm home style, Minimalist, Cinematic...',
    potentialHashtags: 'Potential Hashtags',
    focusHelper: 'Based on your work and platform, here’s what people are most likely to notice',
    suggestTags: 'Suggest Tags',
    regenerate: 'Refresh',
    isCustom: 'Customizable Product',
    generateBtn: 'Generate Content',
    generating: 'AI is working...',
    outputTitle: 'Generated Results',
    outputSub: 'Upload and describe your product to start.',
    rendering: 'Rendering...',
    enhancedImg: 'AI Enhanced Images',
