                      </div>
                      <div className="flex flex-wrap gap-2">
                        {activeContent?.hashtags.map((tag, i) => (
                          <span key={i} className="px-3 py-1 bg-blue-50 border border-blue-100 rounded-full text-[10px] font-black text-blue-600 uppercase shadow-sm">
                            {tag}
                          </span>
