                    </div>

                    {/* Image Prompt Section */}
                    <div className="space-y-2 group">
                      <div className="flex items-center justify-between">
                         <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">{t.imagePrompt}</label>
                         <button 
                          onClick={() => copyToClipboard(activeContent?.image_prompt || '', 'image_prompt')}
                          className="opacity-0 group-hover:opacity-100 p-1.5 rounded-lg hover:bg-slate-100 text-slate-400 transition-all active:scale-90"
                         >
                           {copied === 'image_prompt' ? <Check size={12} className="text-emerald-500" /> : <Copy size={12} />}
                         </button>
                      </div>
                      <div className="p-4 bg-slate-100/50 border border-slate-100 border-dashed rounded-2xl text-[11px] font-medium italic text-slate-500 leading-relaxed shadow-sm">
                        {activeContent?.image_prompt}
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>
        </main>

        <footer className="h-16 flex items-center justify-center border-t border-slate-200 mt-12 bg-white text-[10px] font-black text-slate-400 uppercase tracking-widest flex-shrink-0">
          {t.footer}
        </footer>
      </div>

      <style>{`
        .animate-spin-slow {
          animation: spin 3s linear infinite;
        }
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
        @keyframes bounce-slow {
          0%, 100% { transform: translateY(0) rotate(12deg); }
          50% { transform: translateY(-10px) rotate(12deg); }
        }
        .animate-bounce-slow {
          animation: bounce-slow 2s infinite ease-in-out;
        }
        aside ::-webkit-scrollbar {
          width: 3px;
        }
        aside ::-webkit-scrollbar-thumb {
          background: #E2E8F0;
          border-radius: 10px;
        }
      `}</style>
    </div>
  );
};

