const App = () => {
  const [state, setState] = useState<AppState>({
    originalImages: [],
    enhancedImages: [],
    content: { xiaohongshu: null, instagram: null, facebook: null },
    isGenerating: false,
    activePlatform: 'xiaohongshu',
    stylePreference: '',
    selectedVoiceStyles: {
      xiaohongshu: 'storytelling',
      instagram: 'minimalist',
      facebook: 'friendly_share'
    },
    isCustomizable: false,
    lang: 'zh',
    potentialHashtags: [],
    isGeneratingHashtags: false,
    isAnalyzingImage: false,
    generationCount: 0,
    showSyncModal: false,
    user: null,
    history: [],
    isHistoryOpen: false,
    isFeedbackMode: false
  });
  const [productDesc, setProductDesc] = useState('');
  const [feedbackText, setFeedbackText] = useState('');
  const [copied, setCopied] = useState<string | null>(null);
  const [email, setEmail] = useState('');
  const [isSyncing, setIsSyncing] = useState(false);
  const [showProfileMenu, setShowProfileMenu] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const t = TRANSLATIONS[state.lang];

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setShowProfileMenu(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  useEffect(() => {
    const triggerAutoDescription = async () => {
      if (state.originalImages.length > 0 && !productDesc && !state.isAnalyzingImage) {
        setState(prev => ({ ...prev, isAnalyzingImage: true }));
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
          const visionPrompt = state.lang === 'zh' 
            ? "识别图中展示的一组产品。请基于这些图片，用简短的关键词组合作为描述（例如：毕加索串珠织片、大豆味香薰）。不要写长句，只返回2-4个核心词。"
            : "Identify the product shown in these images. Based on the visuals, provide a brief combination of keywords (e.g., Picasso beaded weave, Soy scented candle). Do not write sentences, only return 2-4 core keywords.";

          // Fix: Explicitly use the Blob type from @google/genai to prevent confusion with browser Blob.
          const parts = state.originalImages.map(img => ({
            inlineData: { data: img.split(',')[1], mimeType: 'image/png' } as Blob
          }));

          const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: {
              parts: [...parts, { text: visionPrompt }]
            }
          });

          if (response.text) {
            setProductDesc(response.text.trim());
          }
        } catch (err) {
          console.error("Auto-description error:", err);
        } finally {
          setState(prev => ({ ...prev, isAnalyzingImage: false }));
        }
      }
    };

    triggerAutoDescription();
  }, [state.originalImages.length]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      const remainingSlots = 3 - state.originalImages.length;
      const filesToProcess = Array.from(files).slice(0, remainingSlots);

      filesToProcess.forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          setState(prev => ({ 
            ...prev, 
            originalImages: [...prev.originalImages, reader.result as string].slice(0, 3)
          }));
        };
        reader.readAsDataURL(file);
      });
    }
    // Reset input value so same file can be re-uploaded if removed
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const removeImage = (index: number) => {
    setState(prev => ({
      ...prev,
      originalImages: prev.originalImages.filter((_, i) => i !== index)
    }));
  };

  const suggestHashtags = async () => {
    if (!productDesc) return;
    setState(prev => ({ ...prev, isGeneratingHashtags: true }));
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      const prompt = `Based on this product description: "${productDesc}", extract 1 to 3 highly relevant and catchy hashtags in ${state.lang === 'zh' ? 'Chinese' : 'English'}. Return ONLY a JSON array of strings. Example: ["#Handmade", "#EcoFriendly"]`;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: 'application/json' }
      });

      const tags = JSON.parse(response.text || '[]');
      setState(prev => ({ ...prev, potentialHashtags: tags, isGeneratingHashtags: false }));
    } catch (err) {
      console.error(err);
      setState(prev => ({ ...prev, isGeneratingHashtags: false }));
    }
  };

  const generateAI = async (withFeedback: boolean = false) => {
    if (state.originalImages.length === 0 || !productDesc) return;
    setState(prev => ({ ...prev, isGenerating: true }));

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      const styleContext = state.stylePreference ? `Follow style: ${state.stylePreference}.` : "Make it look professional and aesthetic.";
      const keywordContext = state.potentialHashtags.length > 0 ? `Incorporate these focus keywords/themes: ${state.potentialHashtags.join(', ')}.` : "";
      const feedbackContext = withFeedback ? `The user has the following special requests/feedback for this regeneration: "${feedbackText}". Please strictly follow these instructions.` : "";
      const noTextInstruction = "IMPORTANT: The generated image must NOT contain any text, words, letters, characters, labels, watermarks, or logos.";

      // We use the first image as the primary reference for generation
      const primaryBase64 = state.originalImages[0].split(',')[1];

      const imagePrompts = [
        `Enhance this product image for social media. ${styleContext} ${keywordContext} ${feedbackContext} High resolution, premium look. ${noTextInstruction}`,
        `Create a stylized lifestyle version of this product. ${styleContext} ${keywordContext} ${feedbackContext} Perfect for social media feed. ${noTextInstruction}`
      ];

      const imagePromises = imagePrompts.map(prompt => 
        ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: {
            parts: [
              { inlineData: { data: primaryBase64, mimeType: 'image/png' } as Blob },
              { text: prompt }
            ]
          }
        })
      );

      const customText = state.isCustomizable ? "Note: This product is customizable." : "";

      const textPrompt = `
        Language: ${state.lang === 'zh' ? 'Chinese' : 'English'}
        Product: ${productDesc}
        Style Preference: ${state.stylePreference || "Modern"}
        Focus Tags: ${state.potentialHashtags.join(', ') || "None specified"}
        ${customText}
        ${feedbackContext}

        Content Tones requested per platform:
        - Xiaohongshu: ${VOICE_STYLES.xiaohongshu.find(v => v.id === state.selectedVoiceStyles.xiaohongshu)?.name.en}
        - Instagram: ${VOICE_STYLES.instagram.find(v => v.id === state.selectedVoiceStyles.instagram)?.name.en}
        - Facebook: ${VOICE_STYLES.facebook.find(v => v.id === state.selectedVoiceStyles.facebook)?.name.en}

        Generate content for Xiaohongshu, Instagram, and Facebook.
        You MUST strictly follow this JSON structure for each platform:
        {
          "title": "A catchy title",
          "body": "The body content, under 300 words, highly engaging with the specified tone.",
          "hashtags": ["#Tag1", "#Tag2", "#Tag3"]
        }

        Provide the output as a combined JSON object with keys: "xiaohongshu", "instagram", "facebook".
      `;

      // Fix: Use Blob type casting to ensure compatibility with Gemini SDK and avoid browser Blob naming collision.
      const imageParts = state.originalImages.map(img => ({
        inlineData: { data: img.split(',')[1], mimeType: 'image/png' } as Blob
      }));

      const textPromise = ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [...imageParts, { text: textPrompt }]
        },
        config: { responseMimeType: 'application/json' }
      });

      const results = (await Promise.all([...imagePromises, textPromise])) as GenerateContentResponse[];
      const [imgRes1, imgRes2, textRes] = results;

      const newImages: string[] = [];
      [imgRes1, imgRes2].forEach(res => {
        // Fix: Narrow down the part type safely before accessing inlineData
        const part = res.candidates?.[0]?.content?.parts.find((p: any) => p.inlineData);
        if (part && 'inlineData' in part && part.inlineData) {
          newImages.push(`data:image/png;base64,${part.inlineData.data}`);
        }
      });

      const jsonText = textRes.text;
      if (!jsonText) throw new Error("No content");
      const content = JSON.parse(jsonText);

      setState(prev => {
        const nextCount = prev.generationCount + 1;
        const newHistoryItem: HistoryItem = {
          id: Math.random().toString(36).substr(2, 9),
          images: prev.originalImages,
          desc: productDesc,
          platform: prev.activePlatform,
          content: content[prev.activePlatform],
          timestamp: Date.now()
        };

        return {
          ...prev,
          enhancedImages: newImages,
          content,
          isGenerating: false,
          generationCount: nextCount,
          showSyncModal: nextCount === 3 && !prev.user ? true : prev.showSyncModal,
          history: [newHistoryItem, ...prev.history],
          isFeedbackMode: false
        };
      });
      setFeedbackText('');

    } catch (err) {
      console.error(err);
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const copyToClipboard = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopied(id);
    setTimeout(() => setCopied(null), 2000);
  };

  const copyAll = () => {
    const active = state.content[state.activePlatform];
    if (!active) return;
    const text = `
【${active.title}】

${active.body}

${active.hashtags.join(' ')}
    `.trim();
    copyToClipboard(text, 'all');
  };

