                      </div>
                      <p className="text-[10px] text-slate-600 font-bold truncate mb-1">{item.desc}</p>
                      <p className="text-[11px] text-slate-800 font-black truncate">{item.content.title}</p>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
