const App = () => {
  const [state, setState] = useState<AppState>({
    originalImages: [],
    modelImage: null,
    enhancedImages: [],
    content: { xiaohongshu: null, instagram: null, facebook: null },
    isGenerating: false,
    activePlatform: 'xiaohongshu',
    stylePreference: '',
    selectedVoiceStyles: {
      xiaohongshu: 'storytelling',
      instagram: 'minimalist',
      facebook: 'friendly_share'
    },
    isCustomizable: false,
    lang: 'zh',
    potentialHashtags: [],
    isGeneratingHashtags: false,
    isAnalyzingImage: false,
    generationCount: 0,
    showSyncModal: false,
    user: null,
    history: [],
    isHistoryOpen: false,
    isFeedbackMode: false
  });
  const [productDesc, setProductDesc] = useState('');
  const [feedbackText, setFeedbackText] = useState('');
  const [copied, setCopied] = useState<string | null>(null);
  const [email, setEmail] = useState('');
  const [isSyncing, setIsSyncing] = useState(false);
  const [showProfileMenu, setShowProfileMenu] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const modelInputRef = useRef<HTMLInputElement>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const t = TRANSLATIONS[state.lang];

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setShowProfileMenu(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  useEffect(() => {
    const triggerAutoDescription = async () => {
      if (state.originalImages.length > 0 && !productDesc && !state.isAnalyzingImage) {
        setState(prev => ({ ...prev, isAnalyzingImage: true }));
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
          const visionPrompt = state.lang === 'zh' 
            ? "识别图中展示的一组产品。请基于这些图片，用简短的关键词组合作为描述（例如：毕加索串珠织片、大豆味香薰）。不要写长句，只返回2-4个核心词。"
            : "Identify the product shown in these images. Based on the visuals, provide a brief combination of keywords (e.g., Picasso beaded weave, Soy scented candle). Do not write sentences, only return 2-4 core keywords.";

          const parts = state.originalImages.map(img => ({
            inlineData: { data: img.split(',')[1], mimeType: 'image/png' } as Blob
          }));

          const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: {
              parts: [...parts, { text: visionPrompt }]
            }
          });

          if (response.text) {
            setProductDesc(response.text.trim());
          }
        } catch (err) {
          console.error("Auto-description error:", err);
        } finally {
          setState(prev => ({ ...prev, isAnalyzingImage: false }));
        }
      }
    };

    triggerAutoDescription();
  }, [state.originalImages.length]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      const remainingSlots = 3 - state.originalImages.length;
      const filesToProcess = Array.from(files).slice(0, remainingSlots);

      filesToProcess.forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          setState(prev => ({ 
            ...prev, 
            originalImages: [...prev.originalImages, reader.result as string].slice(0, 3)
          }));
        };
        reader.readAsDataURL(file);
      });
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleModelUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setState(prev => ({ ...prev, modelImage: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
    if (modelInputRef.current) modelInputRef.current.value = '';
  };

  const removeImage = (index: number) => {
    setState(prev => ({
      ...prev,
      originalImages: prev.originalImages.filter((_, i) => i !== index)
    }));
  };

  const removeModel = () => {
    setState(prev => ({ ...prev, modelImage: null }));
  };

  const suggestHashtags = async () => {
    if (!productDesc) return;
    setState(prev => ({ ...prev, isGeneratingHashtags: true }));
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      const prompt = `Based on this product description: "${productDesc}", extract 1 to 3 highly relevant and catchy hashtags in ${state.lang === 'zh' ? 'Chinese' : 'English'}. Return ONLY a JSON array of strings. Example: ["#Handmade", "#EcoFriendly"]`;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: 'application/json' }
      });

      const tags = JSON.parse(response.text || '[]');
      setState(prev => ({ ...prev, potentialHashtags: tags, isGeneratingHashtags: false }));
    } catch (err) {
      console.error(err);
      setState(prev => ({ ...prev, isGeneratingHashtags: false }));
    }
  };

  const generateAI = async (withFeedback: boolean = false) => {
    if (state.originalImages.length === 0 || !productDesc) return;
    setState(prev => ({ ...prev, isGenerating: true }));

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      const styleContext = state.stylePreference ? `Follow style: ${state.stylePreference}.` : "Make it look professional and aesthetic.";
      const keywordContext = state.potentialHashtags.length > 0 ? `Incorporate these focus keywords/themes: ${state.potentialHashtags.join(', ')}.` : "";
      const feedbackContext = withFeedback ? `The user has the following special requests/feedback for this regeneration: "${feedbackText}". Please strictly follow these instructions.` : "";
      const noTextInstruction = "IMPORTANT: The generated image must NOT contain any text, words, letters, characters, labels, watermarks, or logos.";

      const primaryProductBase64 = state.originalImages[0].split(',')[1];
      const modelBase64 = state.modelImage ? state.modelImage.split(',')[1] : null;

      const baseImagePrompt = `Create a high-quality lifestyle photo for ${PLATFORM_CONFIG[state.activePlatform].name.en}. ${styleContext} ${keywordContext} ${feedbackContext} ${noTextInstruction}`;

      let imagePrompts: any[];
      if (modelBase64) {
        // User provided a model
        const modelPart = { inlineData: { data: modelBase64, mimeType: 'image/png' } as Blob };
        const productPart = { inlineData: { data: primaryProductBase64, mimeType: 'image/png' } as Blob };

        imagePrompts = [
          {
            contents: {
              parts: [
                modelPart,
                productPart,
                { text: `This is a model and this is a product. Generate a photo showing this exact model wearing/using this product. Maintain the model's facial features and overall body shape. ${baseImagePrompt}` }
              ]
            }
          },
          {
            contents: {
              parts: [
                modelPart,
                productPart,
                { text: `A different angle of this same model wearing/using this product in a stylized setting. ${baseImagePrompt}` }
              ]
            }
          }
        ];
      } else {
        // AI generates the model
        imagePrompts = [
          {
            contents: {
              parts: [
                { inlineData: { data: primaryProductBase64, mimeType: 'image/png' } as Blob },
                { text: `Generate a photo featuring an attractive model wearing/using this product. The model's appearance should be tailored for ${PLATFORM_CONFIG[state.activePlatform].name.en} users. ${baseImagePrompt}` }
              ]
            }
          },
          {
            contents: {
              parts: [
                { inlineData: { data: primaryProductBase64, mimeType: 'image/png' } as Blob },
                { text: `A stylized professional product shot of this item being used by a model in a high-end environment. ${baseImagePrompt}` }
              ]
            }
          }
        ];
      }

      const imagePromises = imagePrompts.map(p => 
        ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: p.contents
        })
      );

      const textPrompt = `
        Language: ${state.lang === 'zh' ? 'Chinese' : 'English'}
        Product: ${productDesc}
        Platform: ${PLATFORM_CONFIG[state.activePlatform].name.en}
        Voice Style: ${VOICE_STYLES[state.activePlatform].find(v => v.id === state.selectedVoiceStyles[state.activePlatform])?.name.en}
        Style Preference: ${state.stylePreference || "Modern"}
        Focus Tags: ${state.potentialHashtags.join(', ') || "None specified"}
        ${state.isCustomizable ? "Note: This product is customizable." : ""}
        ${feedbackContext}

        Generate content for Xiaohongshu, Instagram, and Facebook.
        Strictly follow this JSON structure:
        {
          "title": "Catchy title",
          "body": "Engaging body content with the specified tone (under 300 words).",
          "hashtags": ["#Tag1", "#Tag2", "#Tag3"]
        }
        Return combined JSON for all 3 platforms.
      `;

      const textParts: any[] = state.originalImages.map(img => ({
        inlineData: { data: img.split(',')[1], mimeType: 'image/png' } as Blob
      }));
      if (modelBase64) textParts.push({ inlineData: { data: modelBase64, mimeType: 'image/png' } as Blob });

      const textPromise = ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts: [...textParts, { text: textPrompt }] },
        config: { responseMimeType: 'application/json' }
      });

      const results = (await Promise.all([...imagePromises, textPromise])) as GenerateContentResponse[];
      const [imgRes1, imgRes2, textRes] = results;

      const newImages: string[] = [];
      [imgRes1, imgRes2].forEach(res => {
        const part = res.candidates?.[0]?.content?.parts.find((p: any) => p.inlineData);
        if (part && 'inlineData' in part && part.inlineData) {
          newImages.push(`data:image/png;base64,${part.inlineData.data}`);
        }
      });

      const jsonText = textRes.text;
      if (!jsonText) throw new Error("No content");
      const content = JSON.parse(jsonText);

      setState(prev => {
        const nextCount = prev.generationCount + 1;
        const newHistoryItem: HistoryItem = {
          id: Math.random().toString(36).substr(2, 9),
          images: prev.originalImages,
          modelImage: prev.modelImage,
          desc: productDesc,
          platform: prev.activePlatform,
          content: content[prev.activePlatform],
          timestamp: Date.now()
        };

        return {
          ...prev,
          enhancedImages: newImages,
          content,
          isGenerating: false,
          generationCount: nextCount,
          showSyncModal: nextCount === 3 && !prev.user ? true : prev.showSyncModal,
          history: [newHistoryItem, ...prev.history],
          isFeedbackMode: false
        };
      });
      setFeedbackText('');

    } catch (err) {
      console.error(err);
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const copyToClipboard = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopied(id);
    setTimeout(() => setCopied(null), 2000);
  };

  const copyAll = () => {
    const active = state.content[state.activePlatform];
    if (!active) return;
    const text = `【${active.title}】\n\n${active.body}\n\n${active.hashtags.join(' ')}`.trim();
    copyToClipboard(text, 'all');
  };

  const toggleLang = () => {
    setState(prev => ({ ...prev, lang: prev.lang === 'zh' ? 'en' : 'zh' }));
  };

  const handleSyncSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!email) return;
    setIsSyncing(true);
    setTimeout(() => {
      setIsSyncing(false);
      setState(prev => ({ ...prev, showSyncModal: false, user: { email } }));
      alert(t.syncSuccess);
    }, 1500);
  };

  const handleLogout = () => {
    setState(prev => ({ ...prev, user: null, showProfileMenu: false, isHistoryOpen: false }));
  };

  const restoreHistory = (item: HistoryItem) => {
    setState(prev => ({
      ...prev,
      originalImages: item.images,
      modelImage: item.modelImage,
      activePlatform: item.platform,
      content: { ...prev.content, [item.platform]: item.content },
      isHistoryOpen: false
    }));
    setProductDesc(item.desc);
  };

  const updateVoiceStyle = (id: string) => {
    setState(prev => ({
      ...prev,
      selectedVoiceStyles: { ...prev.selectedVoiceStyles, [prev.activePlatform]: id }
    }));
  };

  const activeContent = state.content[state.activePlatform];

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans selection:bg-blue-100 flex overflow-hidden">

      {/* SIDEBAR */}
      <aside className={`fixed inset-y-0 left-0 z-40 w-80 bg-white border-r border-slate-200 transform transition-transform duration-500 ease-in-out shadow-2xl lg:shadow-none ${state.isHistoryOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="h-full flex flex-col">
          <div className="h-16 border-b border-slate-100 flex items-center justify-between px-6">
            <div className="flex items-center gap-2">
              <Clock size={18} className="text-blue-500" />
              <h3 className="font-black text-slate-800 uppercase tracking-widest text-xs">{t.historyTitle}</h3>
            </div>
            <button onClick={() => setState(prev => ({ ...prev, isHistoryOpen: false }))} className="p-1.5 rounded-lg hover:bg-slate-100 text-slate-400 transition-colors">
              <X size={18} />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-4">
            {state.history.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-full text-slate-300 gap-4">
                <History size={48} className="opacity-20" />
                <p className="text-[10px] font-black uppercase tracking-widest">{t.historyEmpty}</p>
              </div>
            ) : (
              state.history.map((item) => (
                <div key={item.id} onClick={() => restoreHistory(item)} className="group p-3 rounded-2xl border border-slate-100 bg-slate-50 hover:bg-white hover:border-blue-200 hover:shadow-lg transition-all cursor-pointer">
                  <div className="flex gap-3">
                    <img src={item.images[0]} className="w-16 h-16 rounded-xl object-cover shadow-sm group-hover:scale-105 transition-transform" />
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-1">
                        <span className={`text-[8px] font-black px-1.5 py-0.5 rounded-md uppercase text-white ${PLATFORM_CONFIG[item.platform].color}`}>
                          {PLATFORM_CONFIG[item.platform].name[state.lang]}
                        </span>
                        <span className="text-[8px] text-slate-400 font-bold">{new Date(item.timestamp).toLocaleDateString()}</span>
                      </div>
                      <p className="text-[10px] text-slate-600 font-bold truncate mb-1">{item.desc}</p>
                      <p className="text-[11px] text-slate-800 font-black truncate">{item.content.title}</p>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      </aside>

      <div className={`flex-1 flex flex-col transition-all duration-500 ${state.isHistoryOpen ? 'lg:ml-80' : 'ml-0'}`}>
        {/* Sync Modal */}
        {state.showSyncModal && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center px-4 overflow-hidden">
            <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300" onClick={() => setState(prev => ({ ...prev, showSyncModal: false }))} />
            <div className="relative w-full max-w-md bg-white rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in slide-in-from-bottom-8 duration-500">
              <button onClick={() => setState(prev => ({ ...prev, showSyncModal: false }))} className="absolute top-6 right-6 p-2 rounded-full bg-slate-50 text-slate-400 hover:text-slate-600 transition-colors">
                <X size={18} />
              </button>
              <div className="flex flex-col items-center text-center space-y-6">
                <div className="w-20 h-20 bg-blue-600 rounded-3xl flex items-center justify-center shadow-xl shadow-blue-600/20 rotate-12 animate-bounce-slow">
                  <Cloud size={40} className="text-white" />
                </div>
                <div className="space-y-2">
                  <h3 className="text-2xl font-black text-slate-900 tracking-tight">{t.syncTitle}</h3>
                  <p className="text-slate-500 text-sm font-medium leading-relaxed">{t.syncDesc}</p>
                </div>
                <form onSubmit={handleSyncSubmit} className="w-full space-y-4">
                  <div className="relative group">
                    <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-blue-500 transition-colors" size={18} />
                    <input type="email" required value={email} onChange={(e) => setEmail(e.target.value)} placeholder={t.emailPlaceholder} className="w-full pl-12 pr-4 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all font-semibold text-slate-700" />
                  </div>
                  <button type="submit" disabled={isSyncing} className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl font-black text-lg flex items-center justify-center gap-2 shadow-xl shadow-blue-600/30 transition-all active:scale-[0.97]">
                    {isSyncing ? <Loader2 className="animate-spin" /> : <><ArrowRight size={20} /> {t.saveAndContinue}</>}
                  </button>
                </form>
              </div>
            </div>
          </div>
        )}

        {/* Header */}
        <nav className="h-16 border-b border-slate-200 bg-white/80 backdrop-blur-md flex items-center justify-between px-6 sticky top-0 z-50">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-xl shadow-lg shadow-blue-600/20 transition-transform hover:scale-105 active:scale-95">
              <ShoppingBag size={20} className="text-white" />
            </div>
            <h1 className="text-xl font-extrabold tracking-tight text-slate-900">{t.brand}</h1>
          </div>

          <div className="flex items-center gap-4">
            <div className="hidden md:flex items-center gap-2 px-3 py-1.5 rounded-full bg-emerald-50 border border-emerald-200">
              <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
              <span className="text-[10px] font-bold text-emerald-700 uppercase tracking-widest">{t.agentReady}</span>
            </div>
            <button onClick={toggleLang} className="flex items-center gap-2 px-3 py-1.5 rounded-lg border border-slate-200 hover:bg-slate-50 transition-all text-xs font-bold text-slate-600 shadow-sm active:scale-95">
              <Globe size={14} />
              {state.lang === 'zh' ? 'English' : '中文'}
            </button>
            {state.user ? (
              <div className="relative" ref={dropdownRef}>
                <button onClick={() => setShowProfileMenu(!showProfileMenu)} className="flex items-center gap-2 pl-2 pr-3 py-1.5 rounded-full border border-slate-200 hover:bg-slate-50 transition-all shadow-sm active:scale-95 group">
                  <div className="w-7 h-7 rounded-full bg-slate-100 border border-slate-200 flex items-center justify-center text-slate-400 group-hover:text-blue-500 group-hover:bg-blue-50 group-hover:border-blue-100 transition-colors"><UserIcon size={14} /></div>
                  <span className="text-xs font-bold text-slate-600 max-w-[100px] truncate">{state.user.email}</span>
                  <ChevronDown size={14} className={`text-slate-400 transition-transform duration-300 ${showProfileMenu ? 'rotate-180' : ''}`} />
                </button>
                {showProfileMenu && (
                  <div className="absolute right-0 mt-2 w-56 bg-white border border-slate-200 rounded-2xl shadow-2xl p-2 z-[60] animate-in fade-in zoom-in slide-in-from-top-2 duration-200">
                    <button onClick={() => { setState(prev => ({ ...prev, isHistoryOpen: true })); setShowProfileMenu(false); }} className="w-full flex items-center gap-3 px-4 py-3 rounded-xl hover:bg-slate-50 transition-colors text-xs font-bold text-slate-600"><History size={16} className="text-blue-500" />{t.viewHistory}</button>
                    <div className="h-px bg-slate-100 my-1" />
                    <button onClick={handleLogout} className="w-full flex items-center gap-3 px-4 py-3 rounded-xl hover:bg-red-50 transition-colors text-xs font-bold text-red-500"><LogOut size={16} />{t.logout}</button>
                  </div>
                )}
              </div>
            ) : (
              <button onClick={() => setState(prev => ({ ...prev, showSyncModal: true }))} className="hidden sm:flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg text-xs font-black uppercase tracking-widest shadow-lg shadow-blue-500/20 active:scale-95 hover:bg-blue-700 transition-all"><Cloud size={14} />{t.saveHistory}</button>
            )}
          </div>
        </nav>

        <main className="max-w-7xl mx-auto w-full p-6 grid grid-cols-1 lg:grid-cols-12 gap-8 overflow-y-auto">

          {/* LEFT: Input Section */}
          <div className="lg:col-span-5 space-y-6">
            <section className="bg-white border border-slate-200 rounded-3xl p-6 space-y-6 shadow-sm transition-all hover:shadow-md">
              <div className="flex items-center gap-2 mb-2">
                <Zap size={18} className="text-blue-500" />
                <h2 className="font-bold text-lg text-slate-800">{t.editorStudio}</h2>
              </div>

              {/* UPLOAD SECTIONS */}
              <div className="space-y-6">
                {/* 1. PRODUCT PHOTOS */}
                <div className="space-y-3">
                  <div className="flex items-center gap-2 text-slate-500">
                    <ImageIcon size={14} />
                    <label className="text-[10px] font-bold uppercase tracking-widest">{t.productPhotos}</label>
                  </div>
                  <div className="grid grid-cols-3 gap-3">
                    {state.originalImages.map((img, idx) => (
                      <div key={idx} className="relative aspect-square group rounded-2xl overflow-hidden border border-slate-100 shadow-sm bg-slate-50 animate-in zoom-in duration-300">
                        <img src={img} alt={`P-${idx}`} className="w-full h-full object-cover transition-transform group-hover:scale-105" />
                        <button onClick={() => removeImage(idx)} className="absolute top-1.5 right-1.5 p-1 bg-white/80 backdrop-blur rounded-full text-slate-600 opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-50 hover:text-red-500"><X size={14} /></button>
                        {idx === 0 && <div className="absolute bottom-0 left-0 right-0 bg-blue-600/80 text-white text-[8px] font-black uppercase py-1 text-center backdrop-blur-sm">Primary</div>}
                      </div>
                    ))}
                    {state.originalImages.length < 3 && (
                      <button onClick={() => fileInputRef.current?.click()} className="aspect-square flex flex-col items-center justify-center border-2 border-dashed border-slate-200 rounded-2xl bg-slate-50 text-slate-400 hover:border-blue-300 hover:bg-blue-50/30 transition-all active:scale-95 group">
                        <Plus size={20} className="group-hover:text-blue-500 transition-colors" />
                        <span className="text-[8px] font-bold mt-1 uppercase">{t.uploadPrompt}</span>
                      </button>
                    )}
                  </div>
                  <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*" multiple />
                </div>

                {/* 2. MODEL PHOTO (Optional) */}
                <div className="space-y-3">
                  <div className="flex items-center gap-2 text-slate-500">
                    <UserCircle size={14} />
                    <label className="text-[10px] font-bold uppercase tracking-widest">{t.modelPhoto}</label>
                  </div>
                  {state.modelImage ? (
                    <div className="relative w-24 aspect-square group rounded-2xl overflow-hidden border-2 border-emerald-100 shadow-sm bg-emerald-50 animate-in zoom-in duration-300">
                      <img src={state.modelImage} alt="Model" className="w-full h-full object-cover" />
                      <button onClick={removeModel} className="absolute top-1 right-1 p-1 bg-white/80 backdrop-blur rounded-full text-slate-600 opacity-0 group-hover:opacity-100 transition-opacity hover:text-red-500"><X size={12} /></button>
                      <div className="absolute bottom-0 left-0 right-0 bg-emerald-500/80 text-white text-[8px] font-black uppercase py-0.5 text-center">User Model</div>
                    </div>
                  ) : (
                    <button onClick={() => modelInputRef.current?.click()} className="w-full h-16 flex items-center justify-center border-2 border-dashed border-slate-200 rounded-2xl bg-slate-50 text-slate-400 hover:border-emerald-300 hover:bg-emerald-50/30 transition-all group">
                      <div className="flex items-center gap-3">
                        <Upload size={18} className="group-hover:text-emerald-500 transition-colors" />
                        <span className="text-xs font-bold uppercase tracking-wide">{t.uploadModelPrompt}</span>
                      </div>
                    </button>
                  )}
                  <input type="file" ref={modelInputRef} onChange={handleModelUpload} className="hidden" accept="image/*" />
                </div>
              </div>

              <div className="space-y-2 relative">
                <div className="flex items-center justify-between">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">{t.productDesc}</label>
                  {state.isAnalyzingImage && <div className="flex items-center gap-1.5 text-[10px] font-bold text-blue-500 animate-pulse"><Wand2 size={12} className="animate-bounce" />{t.analyzingImage}</div>}
                </div>
                <textarea rows={2} value={productDesc} onChange={(e) => setProductDesc(e.target.value)} placeholder={t.productPlaceholder} className={`w-full bg-slate-50 border border-slate-200 rounded-2xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-blue-500/10 focus:border-blue-500 transition-all text-slate-700 font-medium ${state.isAnalyzingImage ? 'opacity-60 cursor-wait' : ''}`} />
              </div>

              <div className="space-y-3">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">{t.publishPlatform}</label>
                <div className="flex bg-slate-100 p-1 rounded-2xl border border-slate-200 shadow-inner">
                  {(['xiaohongshu', 'instagram', 'facebook'] as Platform[]).map((p) => (
                    <button key={p} onClick={() => setState(prev => ({ ...prev, activePlatform: p }))} className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-xl text-xs font-bold transition-all ${state.activePlatform === p ? 'bg-white text-blue-600 shadow-sm border border-slate-200/50' : 'text-slate-400 hover:text-slate-600'}`}>
                      <span>{PLATFORM_CONFIG[p].icon}</span>{PLATFORM_CONFIG[p].name[state.lang]}
                    </button>
                  ))}
                </div>
              </div>

              <div className="space-y-3">
                <div className="flex items-center gap-2 text-slate-500"><Mic2 size={14} /><label className="text-[10px] font-bold uppercase tracking-widest">{t.voiceStyle}</label></div>
                <div className="flex flex-wrap gap-2">
                  {VOICE_STYLES[state.activePlatform].map((style) => (
                    <button key={style.id} onClick={() => updateVoiceStyle(style.id)} className={`px-3 py-1.5 rounded-xl text-[11px] font-bold border transition-all ${state.selectedVoiceStyles[state.activePlatform] === style.id ? 'bg-blue-600 border-blue-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-500 hover:border-blue-200'}`}>{style.name[state.lang]}</button>
                  ))}
                </div>
              </div>

              <div className="space-y-4">
                <div className="space-y-2">
                  <div className="flex items-center gap-2 text-slate-500"><Palette size={14} /><label className="text-[10px] font-bold uppercase tracking-widest">{t.stylePref}</label></div>
                  <input type="text" value={state.stylePreference} onChange={(e) => setState(prev => ({ ...prev, stylePreference: e.target.value }))} placeholder={t.stylePlaceholder} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-sm focus:outline-none focus:border-blue-500 transition-all shadow-sm" />
                </div>
                <div className="space-y-2 p-4 bg-blue-50/50 border border-blue-100/50 rounded-2xl transition-all hover:bg-blue-50">
                  <div className="flex items-center justify-between text-blue-600 mb-1">
                    <div className="flex items-center gap-2"><Hash size={14} /><label className="text-[10px] font-bold uppercase tracking-widest">{t.potentialHashtags}</label></div>
