                    <div className="space-y-2 group"><div className="flex items-center justify-between"><label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Hashtags</label><button onClick={() => copyToClipboard(activeContent?.hashtags.join(' ') || '', 'hashtags')} className="opacity-0 group-hover:opacity-100 p-1.5 rounded-lg hover:bg-slate-100 text-slate-400 transition-all">{copied === 'hashtags' ? <Check size={12} className="text-emerald-500" /> : <Copy size={12} />}</button></div><div className="flex flex-wrap gap-2">{activeContent?.hashtags.map((tag, i) => <span key={i} className="px-3 py-1 bg-blue-50 border border-blue-100 rounded-full text-[10px] font-black text-blue-600 uppercase">{tag}</span>)}</div></div>
