import React, { useState, useRef, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { 
  Sparkles, 
  Image as ImageIcon, 
  Upload, 
  Copy, 
  Check, 
  Loader2, 
  RefreshCw, 
  ShoppingBag, 
  Zap,
  Palette, 
  Settings2,
  Globe,
  Download,
  Hash,
  RotateCcw,
  Wand2,
  Cloud,
  X,
  Mail,
  ArrowRight,
  User as UserIcon,
  LogOut,
  History,
  ChevronDown,
  Clock,
  ClipboardCheck,
  Layout,
  MessageSquarePlus,
  SendHorizontal,
  Mic2,
  Plus,
  UserCircle,
  Shirt
} from 'lucide-react';
// Fix: Removed 'Blob' from import to avoid collision with native browser Blob
import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

// --- Types & Config ---
type Platform = 'xiaohongshu' | 'instagram' | 'facebook';
type Language = 'zh' | 'en';

interface GeneratedContent {
  title: string;
  body: string;
  hashtags: string[];
}

interface HistoryItem {
  id: string;
  images: string[];
  modelImage: string | null;
  desc: string;
  platform: Platform;
  content: GeneratedContent;
  timestamp: number;
}

interface User {
  email: string;
}

interface AppState {
  originalImages: string[];
  modelImage: string | null;
  enhancedImages: string[];
  content: Record<Platform, GeneratedContent | null>;
  isGenerating: boolean;
  activePlatform: Platform;
  stylePreference: string;
  selectedVoiceStyles: Record<Platform, string>;
  isCustomizable: boolean;
  lang: Language;
  potentialHashtags: string[];
  isGeneratingHashtags: boolean;
  isAnalyzingImage: boolean;
  generationCount: number;
  showSyncModal: boolean;
  user: null | User;
  history: HistoryItem[];
  isHistoryOpen: boolean;
  isFeedbackMode: boolean;
}

const VOICE_STYLES = {
  xiaohongshu: [
