    { id: "storytelling", name: { zh: "故事共鸣型", en: "Storytelling" }, default: true },
    { id: "tutorial", name: { zh: "干货教程型", en: "Educational" } },
    { id: "soothing", name: { zh: "温柔治愈型", en: "Healing/Soothing" } }
  ],
  instagram: [
    { id: "minimalist", name: { zh: "极简美学型", en: "Minimalist" }, default: true },
    { id: "self_expression", name: { zh: "自我表达型", en: "Self-Expression" } },
    { id: "light_story", name: { zh: "轻故事型", en: "Short Story" } }
  ],
