        </main>
        <footer className="h-16 flex items-center justify-center border-t border-slate-200 mt-12 bg-white text-[10px] font-black text-slate-400 uppercase tracking-widest flex-shrink-0">{t.footer}</footer>
      </div>
    </div>
  );
};

const container = document.getElementById('root');
if (container) {
