  lang: Language;
  potentialHashtags: string[];
  isGeneratingHashtags: boolean;
  isAnalyzingImage: boolean;
  generationCount: number;
  showSyncModal: boolean;
  user: null | User;
  history: HistoryItem[];
  isHistoryOpen: boolean;
  isFeedbackMode: boolean;
}

