const App = () => {
  const [state, setState] = useState<AppState>({
    originalImages: [],
    modelImage: null,
    enhancedImages: [],
    content: { xiaohongshu: null, instagram: null, facebook: null },
    isGenerating: false,
    activePlatform: 'xiaohongshu',
    stylePreference: '',
    selectedVoiceStyles: {
      xiaohongshu: 'storytelling',
      instagram: 'minimalist',
      facebook: 'friendly_share'
    },
    isCustomizable: false,
    lang: 'zh',
    potentialHashtags: [],
    isGeneratingHashtags: false,
    isAnalyzingImage: false,
    generationCount: 0,
    showSyncModal: false,
    user: null,
    history: [],
    isHistoryOpen: false,
    isFeedbackMode: false
  });
  const [productDesc, setProductDesc] = useState('');
  const [feedbackText, setFeedbackText] = useState('');
  const [copied, setCopied] = useState<string | null>(null);
  const [showProfileMenu, setShowProfileMenu] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const modelInputRef = useRef<HTMLInputElement>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const t = TRANSLATIONS[state.lang];

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setShowProfileMenu(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  useEffect(() => {
    const triggerAutoDescription = async () => {
      if (state.originalImages.length > 0 && !productDesc && !state.isAnalyzingImage) {
        setState(prev => ({ ...prev, isAnalyzingImage: true }));
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
          const visionPrompt = state.lang === 'zh' 
            ? "识别图中展示的一组产品。请基于这些图片，用简短的关键词组合作为描述。不要写长句，只返回2-4个核心词。"
            : "Identify the product in these images. Provide a brief combination of keywords. Return ONLY 2-4 keywords.";

          const parts = state.originalImages.map(img => ({
            inlineData: { data: img.split(',')[1], mimeType: 'image/png' }
          }));

          const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: { parts: [...parts, { text: visionPrompt }] }
          });

          if (response.text) {
            setProductDesc(response.text.trim());
          }
        } catch (err) {
          console.error("Auto-description error:", err);
        } finally {
          setState(prev => ({ ...prev, isAnalyzingImage: false }));
        }
      }
    };

    triggerAutoDescription();
  }, [state.originalImages.length, state.lang]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      const remainingSlots = 3 - state.originalImages.length;
      const filesToProcess = Array.from(files).slice(0, remainingSlots);

      filesToProcess.forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          setState(prev => ({ 
            ...prev, 
            originalImages: [...prev.originalImages, reader.result as string].slice(0, 3)
          }));
        };
        reader.readAsDataURL(file);
      });
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleModelUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setState(prev => ({ ...prev, modelImage: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
    if (modelInputRef.current) modelInputRef.current.value = '';
  };

  const removeImage = (index: number) => {
    setState(prev => ({
      ...prev,
      originalImages: prev.originalImages.filter((_, i) => i !== index)
    }));
  };

  const removeModel = () => {
    setState(prev => ({ ...prev, modelImage: null }));
  };

  const suggestHashtags = async () => {
    if (!productDesc) return;
    setState(prev => ({ ...prev, isGeneratingHashtags: true }));
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      const prompt = `Based on: "${productDesc}", extract 3-5 highly relevant hashtags in ${state.lang === 'zh' ? 'Chinese' : 'English'}. Return ONLY a JSON array of strings.`;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: 'application/json' }
      });

      const tags = JSON.parse(response.text || '[]');
      setState(prev => ({ ...prev, potentialHashtags: Array.isArray(tags) ? tags : [], isGeneratingHashtags: false }));
    } catch (err) {
      console.error(err);
      setState(prev => ({ ...prev, isGeneratingHashtags: false }));
    }
  };

  const generateAI = async (withFeedback: boolean = false) => {
    if (state.originalImages.length === 0 || !productDesc) return;
    setState(prev => ({ ...prev, isGenerating: true }));

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      const styleContext = state.stylePreference ? `Style: ${state.stylePreference}.` : "High-end, professional social media aesthetics.";
      const keywordContext = state.potentialHashtags.length > 0 ? `Themes/Tags to include: ${state.potentialHashtags.join(', ')}.` : "";
      const customContext = state.isCustomizable ? "The product is CUSTOMIZABLE. Emphasize personalized features and uniqueness in the copy." : "";
      const feedbackContext = withFeedback ? `Feedback instruction: "${feedbackText}". Strictly follow this.` : "";
      const noTextInstruction = "The generated image must NOT contain any text, watermarks, or logos.";

      const primaryProductBase64 = state.originalImages[0].split(',')[1];
      const modelBase64 = state.modelImage ? state.modelImage.split(',')[1] : null;

      const baseImagePrompt = `Professional fashion/lifestyle photo for ${PLATFORM_CONFIG[state.activePlatform].name.en}. ${styleContext} ${keywordContext} ${customContext} ${feedbackContext} ${noTextInstruction}`;

      let imagePrompts: any[];
      if (modelBase64) {
        const modelPart = { inlineData: { data: modelBase64, mimeType: 'image/png' } };
        const productPart = { inlineData: { data: primaryProductBase64, mimeType: 'image/png' } };

        imagePrompts = [
          {
            contents: {
              parts: [
                modelPart,
                productPart,
                { text: `VIRTUAL TRY-ON: Reference model and product. Generate photo showing this model wearing/using this product. Maintain identity. ${baseImagePrompt}` }
              ]
            }
          },
          {
            contents: {
              parts: [
                modelPart,
                productPart,
                { text: `Different lifestyle pose for the same model identity. ${baseImagePrompt}` }
              ]
            }
          }
        ];
      } else {
        imagePrompts = [
          {
            contents: {
              parts: [
                { inlineData: { data: primaryProductBase64, mimeType: 'image/png' } },
                { text: `Generate a trendy model wearing this product for ${PLATFORM_CONFIG[state.activePlatform].name.en}. ${baseImagePrompt}` }
              ]
            }
          },
          {
            contents: {
              parts: [
                { inlineData: { data: primaryProductBase64, mimeType: 'image/png' } },
                { text: `Editorial lifestyle shot of a model with this product. ${baseImagePrompt}` }
              ]
            }
          }
        ];
      }

      const imagePromises = imagePrompts.map(p => ai.models.generateContent({ model: 'gemini-2.5-flash-image', contents: p.contents }));

      const textPrompt = `
        Language: ${state.lang === 'zh' ? 'Chinese' : 'English'}
        Product: ${productDesc}
        Platform: ${PLATFORM_CONFIG[state.activePlatform].name.en}
        Tone: ${VOICE_STYLES[state.activePlatform].find(v => v.id === state.selectedVoiceStyles[state.activePlatform])?.name.en}
        ${customContext}
        ${feedbackContext}
        Generate optimized content in JSON for all 3 platforms: "xiaohongshu", "instagram", "facebook".
        Format: { "xiaohongshu": { "title": "...", "body": "...", "hashtags": [] }, "instagram": { ... }, "facebook": { ... } }
      `;

      const textParts: any[] = state.originalImages.map(img => ({ inlineData: { data: img.split(',')[1], mimeType: 'image/png' } }));
      if (modelBase64) textParts.push({ inlineData: { data: modelBase64, mimeType: 'image/png' } });

      const textPromise = ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts: [...textParts, { text: textPrompt }] },
        config: { responseMimeType: 'application/json' }
      });

      const results = (await Promise.all([...imagePromises, textPromise])) as GenerateContentResponse[];
      const [imgRes1, imgRes2, textRes] = results;

      const newImages: string[] = [];
      [imgRes1, imgRes2].forEach(res => {
        const parts = res.candidates?.[0]?.content?.parts;
        if (parts) {
          for (const part of parts) {
            if (part.inlineData) {
              const base64Data: string = part.inlineData.data;
              newImages.push(`data:image/png;base64,${base64Data}`);
              break;
            }
          }
        }
      });

      const jsonText = textRes.text;
      if (!jsonText) throw new Error("No text content returned");
      const content = JSON.parse(jsonText);

      setState(prev => {
        const activeData = content[prev.activePlatform] || { title: "Untitled", body: "", hashtags: [] };
        const updatedContent = { ...prev.content, ...content };
        const nextCount = prev.generationCount + 1;
        const newHistoryItem: HistoryItem = {
          id: Math.random().toString(36).substr(2, 9),
          images: prev.originalImages,
          modelImage: prev.modelImage,
          desc: productDesc,
          platform: prev.activePlatform,
          content: activeData,
          timestamp: Date.now()
        };
        return { 
          ...prev, 
          enhancedImages: newImages, 
          content: updatedContent, 
          isGenerating: false, 
          generationCount: nextCount, 
          showSyncModal: nextCount === 3 && !prev.user ? true : prev.showSyncModal, 
          history: [newHistoryItem, ...prev.history], 
          isFeedbackMode: false 
        };
      });
      setFeedbackText('');
    } catch (err) {
      console.error("Generation Error:", err);
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const copyToClipboard = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopied(id);
    setTimeout(() => setCopied(null), 2000);
  };

  const copyAll = () => {
    const active = state.content[state.activePlatform];
    if (!active) return;
    const text = `【${active?.title || ''}】\n\n${active?.body || ''}\n\n${active?.hashtags?.join(' ') || ''}`.trim();
    copyToClipboard(text, 'all');
  };

  const toggleLang = () => setState(prev => ({ ...prev, lang: prev.lang === 'zh' ? 'en' : 'zh' }));

  const restoreHistory = (item: HistoryItem) => {
    setState(prev => ({ 
      ...prev, 
      originalImages: item.images, 
      modelImage: item.modelImage, 
      activePlatform: item.platform, 
      content: { ...prev.content, [item.platform]: item.content }, 
      isHistoryOpen: false 
    }));
    setProductDesc(item.desc);
  };

  const updateVoiceStyle = (id: string) => setState(prev => ({ ...prev, selectedVoiceStyles: { ...prev.selectedVoiceStyles, [prev.activePlatform]: id } }));

  const activeContent = state.content[state.activePlatform];

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans flex overflow-hidden">

      {/* SIDEBAR HISTORY */}
      <aside className={`fixed inset-y-0 left-0 z-40 w-80 bg-white border-r border-slate-200 transform transition-transform duration-500 ease-in-out ${state.isHistoryOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="h-full flex flex-col">
          <div className="h-16 border-b border-slate-100 flex items-center justify-between px-6">
            <div className="flex items-center gap-2">
              <Clock size={18} className="text-blue-500" />
              <h3 className="font-black text-slate-800 uppercase tracking-widest text-xs">{t.historyTitle}</h3>
            </div>
            <button onClick={() => setState(prev => ({ ...prev, isHistoryOpen: false }))} className="p-1.5 rounded-lg hover:bg-slate-100 text-slate-400 transition-colors">
              <X size={18} />
            </button>
          </div>
          <div className="flex-1 overflow-y-auto p-4 space-y-4">
            {state.history.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-full text-slate-300 gap-4">
                <History size={48} className="opacity-20" />
                <p className="text-[10px] font-black uppercase tracking-widest">{t.historyEmpty}</p>
              </div>
            ) : (
              state.history.map((item) => (
                <div key={item.id} onClick={() => restoreHistory(item)} className="group p-3 rounded-2xl border border-slate-100 bg-slate-50 hover:bg-white hover:border-blue-200 hover:shadow-lg transition-all cursor-pointer">
                  <div className="flex gap-3">
                    <img src={item.images[0]} className="w-16 h-16 rounded-xl object-cover" alt="Thumb" />
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-1">
                        <span className={`text-[8px] font-black px-1.5 py-0.5 rounded-md uppercase text-white ${PLATFORM_CONFIG[item.platform].color}`}>{PLATFORM_CONFIG[item.platform].name[state.lang]}</span>
                        <span className="text-[8px] text-slate-400 font-bold">{new Date(item.timestamp).toLocaleDateString()}</span>
                      </div>
                      <p className="text-[10px] text-slate-600 font-bold truncate mb-1">{item.desc}</p>
                      <p className="text-[11px] text-slate-800 font-black truncate">{item.content?.title || "Untitled"}</p>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      </aside>

      <div className={`flex-1 flex flex-col transition-all duration-500 ${state.isHistoryOpen ? 'lg:ml-80' : 'ml-0'}`}>

        {/* Header */}
        <nav className="h-16 border-b border-slate-200 bg-white/80 backdrop-blur-md flex items-center justify-between px-6 sticky top-0 z-50">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-xl shadow-lg shadow-blue-600/20"><ShoppingBag size={20} className="text-white" /></div>
            <h1 className="text-xl font-extrabold tracking-tight text-slate-900">{t.brand}</h1>
          </div>
          <div className="flex items-center gap-4">
            <button onClick={toggleLang} className="flex items-center gap-2 px-3 py-1.5 rounded-lg border border-slate-200 hover:bg-slate-50 transition-all text-xs font-bold text-slate-600 shadow-sm">
              <Globe size={14} />{state.lang === 'zh' ? 'English' : '中文'}
            </button>
            <button onClick={() => setState(prev => ({ ...prev, isHistoryOpen: !prev.isHistoryOpen }))} className="p-2 bg-slate-100 text-slate-600 rounded-lg hover:bg-blue-50 hover:text-blue-600 transition-all">
              <History size={18} />
            </button>
          </div>
        </nav>

        <main className="max-w-7xl mx-auto w-full p-6 grid grid-cols-1 lg:grid-cols-12 gap-8 overflow-y-auto">

          {/* LEFT: Editor Studio */}
          <div className="lg:col-span-5 space-y-6">
            <section className="bg-white border border-slate-200 rounded-3xl p-6 space-y-6 shadow-sm transition-all hover:shadow-md">
              <div className="flex items-center gap-2 mb-2">
                <Zap size={18} className="text-blue-500" />
                <h2 className="font-bold text-lg text-slate-800">{t.editorStudio}</h2>
              </div>

              {/* DUAL UPLOAD SYSTEM */}
              <div className="grid grid-cols-1 gap-6">

                {/* 1. PRODUCT SECTION */}
                <div className="space-y-3">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2 text-slate-500">
                      <ImageIcon size={14} />
                      <label className="text-[10px] font-bold uppercase tracking-widest">{t.productPhotos}</label>
                    </div>
                  </div>
                  <div className="grid grid-cols-3 gap-3">
                    {state.originalImages.map((img, idx) => (
                      <div key={idx} className="relative aspect-square group rounded-2xl overflow-hidden border border-slate-100 shadow-sm bg-slate-50">
                        <img src={img} className="w-full h-full object-cover" alt={`Product ${idx}`} />
                        <button onClick={() => removeImage(idx)} className="absolute top-1 right-1 p-1 bg-white/80 backdrop-blur rounded-full text-slate-600 opacity-0 group-hover:opacity-100 transition-opacity"><X size={12} /></button>
                      </div>
                    ))}
                    {state.originalImages.length < 3 && (
                      <button onClick={() => fileInputRef.current?.click()} className="aspect-square flex flex-col items-center justify-center border-2 border-dashed border-slate-200 rounded-2xl bg-slate-50 text-slate-400 hover:border-blue-300 hover:bg-blue-50/30 transition-all group">
                        <Plus size={20} />
                        <span className="text-[8px] font-bold mt-1 uppercase">{t.uploadPrompt}</span>
                      </button>
                    )}
                  </div>
                  <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*" multiple />
                </div>

                {/* 2. MODEL SECTION */}
                <div className="space-y-3 border-t border-slate-50 pt-4">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2 text-slate-500">
                      <UserCircle size={14} />
                      <label className="text-[10px] font-bold uppercase tracking-widest">{t.modelPhoto}</label>
                    </div>
                  </div>
                  <div className="flex items-center gap-3">
                    {state.modelImage ? (
                      <div className="relative w-24 aspect-square group rounded-2xl overflow-hidden border-2 border-emerald-500 shadow-sm bg-emerald-50">
                        <img src={state.modelImage} className="w-full h-full object-cover" alt="Model Ref" />
                        <button onClick={removeModel} className="absolute top-1 right-1 p-1 bg-white/80 backdrop-blur rounded-full text-slate-600 opacity-0 group-hover:opacity-100 transition-opacity"><X size={12} /></button>
                      </div>
                    ) : (
                      <button onClick={() => modelInputRef.current?.click()} className="flex-1 h-24 flex flex-col items-center justify-center border-2 border-dashed border-emerald-100 rounded-2xl bg-emerald-50/20 text-emerald-600 hover:bg-emerald-50/50 transition-all group">
                        <Shirt size={20} className="mb-1" />
                        <span className="text-[10px] font-bold uppercase">{t.uploadModelPrompt}</span>
                      </button>
                    )}
                    <div className="flex-1 text-[10px] text-slate-400 leading-tight italic py-2">
                      {t.autoModelHint}
                    </div>
                  </div>
                  <input type="file" ref={modelInputRef} onChange={handleModelUpload} className="hidden" accept="image/*" />
                </div>
              </div>

              {/* INPUT FIELDS */}
              <div className="space-y-4 pt-4 border-t border-slate-50">
                <div className="space-y-2 relative">
                  <div className="flex items-center justify-between">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">{t.productDesc}</label>
                    {state.isAnalyzingImage && <span className="text-[10px] text-blue-500 font-bold animate-pulse">{t.analyzingImage}</span>}
                  </div>
