                  </div>
                  <div className="space-y-6">
                    <div className="space-y-2 group">
                      <div className="flex items-center justify-between">
                        <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">{t.suggestedTitle}</label>
                        <button onClick={() => copyToClipboard(activeContent?.title || '', 'title')} className="p-1.5 rounded-lg text-slate-300 hover:text-blue-500 hover:bg-blue-50 transition-all">
                          {copied === 'title' ? <Check size={14} className="text-emerald-500" /> : <Copy size={14} />}
                        </button>
                      </div>
                      <div className="p-5 bg-slate-50 border border-slate-100 rounded-2xl text-lg font-extrabold text-slate-800 shadow-inner">{activeContent?.title || "Untitled"}</div>
                    </div>

                    <div className="space-y-2 group">
                      <div className="flex items-center justify-between">
                        <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">{t.bodyText}</label>
                        <button onClick={() => copyToClipboard(activeContent?.body || '', 'body')} className="p-1.5 rounded-lg text-slate-300 hover:text-blue-500 hover:bg-blue-50 transition-all">
                          {copied === 'body' ? <Check size={14} className="text-emerald-500" /> : <Copy size={14} />}
                        </button>
                      </div>
                      <div className="p-5 bg-slate-50 border border-slate-100 rounded-2xl text-sm leading-relaxed text-slate-600 whitespace-pre-wrap min-h-[140px] shadow-inner font-semibold">{activeContent?.body || ""}</div>
                    </div>

                    <div className="space-y-2 group">
                      <div className="flex items-center justify-between">
                        <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Hashtags</label>
                        <button onClick={() => copyToClipboard((activeContent?.hashtags || []).join(' '), 'hashtags')} className="p-1.5 rounded-lg text-slate-300 hover:text-blue-500 hover:bg-blue-50 transition-all">
                          {copied === 'hashtags' ? <Check size={14} className="text-emerald-500" /> : <Copy size={14} />}
                        </button>
                      </div>
                      <div className="flex flex-wrap gap-2">
                        {(activeContent?.hashtags || []).map((tag, i) => (
                          <span key={i} className="px-3 py-1 bg-blue-50 border border-blue-100 rounded-full text-[10px] font-black text-blue-600 uppercase">#{tag}</span>
                        ))}
                      </div>
                    </div>
                  </div>
                  <div className="pt-8 border-t border-slate-100">
                    {!state.isFeedbackMode ? <button onClick={() => setState(prev => ({ ...prev, isFeedbackMode: true }))} className="flex items-center gap-2 text-[11px] font-black text-slate-400 uppercase tracking-widest hover:text-blue-500 transition-colors group"><MessageSquarePlus size={16} className="group-hover:scale-110 transition-transform" />{t.notSatisfied}</button> : (
                      <div className="space-y-4 animate-in fade-in slide-in-from-top-2"><textarea value={feedbackText} onChange={(e) => setFeedbackText(e.target.value)} placeholder={t.feedbackPlaceholder} className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/10 focus:border-blue-500 transition-all min-h-[80px] font-medium text-slate-700 shadow-inner" /><div className="flex items-center gap-3"><button onClick={() => generateAI(true)} className="flex-1 py-3 bg-blue-600 text-white rounded-xl text-xs font-black uppercase tracking-widest shadow-lg hover:bg-blue-700 active:scale-95 transition-all flex items-center justify-center gap-2"><SendHorizontal size={14} />{t.submitFeedback}</button><button onClick={() => setState(prev => ({ ...prev, isFeedbackMode: false }))} className="px-4 py-3 bg-slate-100 text-slate-500 rounded-xl text-xs font-black uppercase tracking-widest hover:bg-slate-200 transition-all">{state.lang === 'zh' ? '取消' : 'Cancel'}</button></div></div>
                    )}
                  </div>
                </div>
              </div>
            )}
          </div>
        </main>
        <footer className="h-16 flex items-center justify-center border-t border-slate-200 mt-12 bg-white text-[10px] font-black text-slate-400 uppercase tracking-widest flex-shrink-0">{t.footer}</footer>
      </div>
    </div>
  );
};

