          <div className={`p-2 rounded-xl transition-colors ${state.activeTab === 'results' ? 'bg-blue-50' : ''}`}><Sparkles size={20} strokeWidth={state.activeTab === 'results' ? 2.5 : 2} /></div>
          <span className="text-[8px] font-black uppercase tracking-widest">{t.results}</span>
        </button>
        <button onClick={() => setState(p => ({ ...p, activeTab: 'archive' }))} className={`flex flex-col items-center gap-1 transition-all ${state.activeTab === 'archive' ? 'text-blue-600' : 'text-slate-300'}`}>
          <div className={`p-2 rounded-xl transition-colors ${state.activeTab === 'archive' ? 'bg-blue-50' : ''}`}><Library size={20} strokeWidth={state.activeTab === 'archive' ? 2.5 : 2} /></div>
          <span className="text-[8px] font-black uppercase tracking-widest">{t.archive}</span>
        </button>
      </nav>

      {/* GLOBAL OVERLAYS */}
      {state.isGenerating && (
        <div className="absolute inset-0 z-[100] bg-white/60 backdrop-blur-sm flex flex-col items-center justify-center space-y-4 animate-in fade-in duration-300">
           <div className="bg-white p-10 rounded-[40px] shadow-2xl flex flex-col items-center space-y-6">
              <div className="w-12 h-12 border-4 border-blue-100 border-b-blue-600 rounded-full animate-spin" />
              <p className="text-[10px] font-black text-blue-600 uppercase tracking-[0.2em]">{t.generating}</p>
           </div>
        </div>
      )}
    </div>
  );
};

const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(<App />);
}

