    outputTitle: 'Your Inspiration',
    outputSub: 'Results will appear here',
    enhancedImg: 'AI Enhanced',
    copyBtn: 'Copy',
    copyAll: 'Copy All',
    suggestedTitle: 'Viral Title',
    bodyText: 'Optimized Copy',
    notSatisfied: 'Not satisfied? Tell AI',
    submitFeedback: 'Regenerate',
    analyzingImage: 'Analyzing...'
  }
};

const App = () => {
  const [state, setState] = useState<AppState>({
    originalImages: [],
    modelImage: null,
    enhancedImages: [],
    content: { xiaohongshu: null, instagram: null, facebook: null },
    isGenerating: false,
    activePlatform: 'xiaohongshu',
    stylePreference: '',
    selectedVoiceStyles: {
      xiaohongshu: 'storytelling',
      instagram: 'minimalist',
      facebook: 'friendly_share'
    },
    isCustomizable: false,
    lang: 'zh',
    potentialHashtags: [],
    isGeneratingHashtags: false,
    isAnalyzingImage: false,
    activeTab: 'studio',
    history: [],
    isFeedbackMode: false
  });
  const [productDesc, setProductDesc] = useState('');
  const [feedbackText, setFeedbackText] = useState('');
  const [copied, setCopied] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const modelInputRef = useRef<HTMLInputElement>(null);

  const t = TRANSLATIONS[state.lang];

  useEffect(() => {
    const triggerAutoDescription = async () => {
      if (state.originalImages.length > 0 && !productDesc && !state.isAnalyzingImage) {
        setState(prev => ({ ...prev, isAnalyzingImage: true }));
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        try {
          const visionPrompt = state.lang === 'zh' 
            ? "识别图中展示的一组产品。请基于这些图片，用简短的关键词组合作为描述。不要写长句，只返回2-4个核心词。"
            : "Identify the product in these images. Provide a brief combination of keywords. Return ONLY 2-4 keywords.";

          const parts = state.originalImages.map(img => ({
            inlineData: { data: img.split(',')[1] || '', mimeType: 'image/png' } as Blob
          }));
          const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: { parts: [...parts, { text: visionPrompt }] }
          });
          if (response.text) setProductDesc(response.text.trim());
        } catch (err) {
          console.error("Auto-description error:", err);
        } finally {
          setState(prev => ({ ...prev, isAnalyzingImage: false }));
        }
      }
    };
    triggerAutoDescription();
  }, [state.originalImages.length, state.isAnalyzingImage, state.lang, productDesc]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      const remainingSlots = 3 - state.originalImages.length;
      const filesToProcess = Array.from(files).slice(0, remainingSlots);
      filesToProcess.forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          setState(prev => ({ 
            ...prev, 
            originalImages: [...prev.originalImages, reader.result as string].slice(0, 3)
          }));
        };
        reader.readAsDataURL(file);
      });
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleModelUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setState(prev => ({ ...prev, modelImage: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
    if (modelInputRef.current) modelInputRef.current.value = '';
  };

  const suggestHashtags = async () => {
    if (!productDesc) return;
    setState(prev => ({ ...prev, isGeneratingHashtags: true }));
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const prompt = `Based on: "${productDesc}", extract 3-5 highly relevant hashtags in ${state.lang === 'zh' ? 'Chinese' : 'English'}. Return ONLY a JSON array of strings.`;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: 'application/json' }
      });
      const tags = JSON.parse(response.text || '[]');
      setState(prev => ({ ...prev, potentialHashtags: Array.isArray(tags) ? tags : [], isGeneratingHashtags: false }));
    } catch (err) {
      setState(prev => ({ ...prev, isGeneratingHashtags: false }));
    }
  };

  const generateAI = async (withFeedback: boolean = false) => {
    if (state.originalImages.length === 0 || !productDesc) return;
    setState(prev => ({ ...prev, isGenerating: true }));

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const styleContext = state.stylePreference ? `Style: ${state.stylePreference}.` : "High-end social media visuals.";
      const keywordContext = state.potentialHashtags.length > 0 ? `Tags: ${state.potentialHashtags.join(', ')}.` : "";
      const customContext = state.isCustomizable ? "STRESS that the product is CUSTOMIZABLE and bespoke." : "";
      const feedbackContext = withFeedback ? `User requested changes: "${feedbackText}".` : "";
      const noTextInstruction = "IMPORTANT: THE GENERATED IMAGE MUST NOT CONTAIN ANY TEXT, LOGOS, OR WATERMARKS. JUST A CLEAN PHOTO.";

      const primaryProductBase64 = state.originalImages[0].split(',')[1] || '';
      const modelBase64Raw = state.modelImage ? state.modelImage.split(',')[1] : null;

      const baseImagePrompt = `Clean professional lifestyle photo for ${PLATFORM_CONFIG[state.activePlatform].name.en}. ${styleContext} ${keywordContext} ${customContext} ${feedbackContext} ${noTextInstruction}`;

      let contentsForImageGen: any[] = [];
      if (modelBase64Raw) {
        contentsForImageGen = [
          {
            parts: [
              { inlineData: { data: modelBase64Raw, mimeType: 'image/png' } as Blob },
              { inlineData: { data: primaryProductBase64, mimeType: 'image/png' } as Blob },
              { text: `VIRTUAL TRY-ON: Show this model wearing this product. ${baseImagePrompt}` }
            ]
          },
          {
            parts: [
              { inlineData: { data: modelBase64Raw, mimeType: 'image/png' } as Blob },
              { inlineData: { data: primaryProductBase64, mimeType: 'image/png' } as Blob },
              { text: `A different elegant pose for the same model. ${baseImagePrompt}` }
            ]
          }
        ];
      } else {
        contentsForImageGen = [
          {
            parts: [
              { inlineData: { data: primaryProductBase64, mimeType: 'image/png' } as Blob },
              { text: `Modern model showcasing this product. ${baseImagePrompt}` }
            ]
          },
          {
            parts: [
              { inlineData: { data: primaryProductBase64, mimeType: 'image/png' } as Blob },
              { text: `A high-end product lifestyle shot. ${baseImagePrompt}` }
            ]
          }
        ];
      }

      const imagePromises: Promise<GenerateContentResponse>[] = contentsForImageGen.map(c => ai.models.generateContent({ 
        model: 'gemini-2.5-flash-image', 
        contents: c 
      }));

      const textPrompt = `
        Language: ${state.lang === 'zh' ? 'Chinese' : 'English'}
        Product: ${productDesc}
        Platform: ${PLATFORM_CONFIG[state.activePlatform].name.en}
        Tone: ${VOICE_STYLES[state.activePlatform].find(v => v.id === state.selectedVoiceStyles[state.activePlatform])?.name.en}
        ${customContext}
        ${feedbackContext}
        Return JSON ONLY: { "xiaohongshu": { "title": "...", "body": "...", "hashtags": [] }, "instagram": { ... }, "facebook": { ... } }
      `;

      const textParts = state.originalImages.map(img => ({ inlineData: { data: img.split(',')[1] || '', mimeType: 'image/png' } as Blob }));
      const textPromise: Promise<GenerateContentResponse> = ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts: [...textParts, { text: textPrompt }] },
        config: { responseMimeType: 'application/json' }
      });

      const results: GenerateContentResponse[] = await Promise.all([...imagePromises, textPromise]);

      const newImages: string[] = [];
      results.slice(0, 2).forEach(res => {
        const parts = res.candidates?.[0]?.content?.parts;
        if (parts) {
          for (const part of parts) {
            if (part.inlineData) {
              const base64Data = (part.inlineData as Blob).data;
              newImages.push(`data:image/png;base64,${base64Data}`);
              break;
            }
          }
        }
      });

      const content = JSON.parse(results[2].text || '{}');
      const activeData = content[state.activePlatform] || { title: "", body: "", hashtags: [] };

      const newHistoryItem: HistoryItem = {
        id: Math.random().toString(36).substr(2, 9),
        images: state.originalImages,
        modelImage: state.modelImage,
        desc: productDesc,
        platform: state.activePlatform,
        content: activeData,
        timestamp: Date.now()
      };

      setState(prev => ({ 
        ...prev, 
        enhancedImages: newImages, 
        content: { ...prev.content, ...content }, 
        isGenerating: false, 
        activeTab: 'results',
        history: [newHistoryItem, ...prev.history],
        isFeedbackMode: false 
      }));
      setFeedbackText('');
    } catch (err) {
      console.error(err);
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const copyToClipboard = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopied(id);
    setTimeout(() => setCopied(null), 2000);
  };

  const activeContent = state.content[state.activePlatform];

  return (
    <div className="min-h-screen bg-[#F1F5F9] flex flex-col relative">
      {/* 灵动岛装饰 (响应式顶栏) */}
      <div className="hidden sm:flex absolute top-2 left-1/2 -translate-x-1/2 w-32 h-8 bg-black rounded-full z-[100] items-center justify-center gap-2 overflow-hidden shadow-lg">
        <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse"></div>
        <span className="text-[10px] font-bold text-white uppercase tracking-tighter opacity-80">AI Running</span>
      </div>

      {/* APP HEADER */}
      <header className="h-16 bg-white/80 backdrop-blur-xl flex items-center justify-between px-6 sticky top-0 z-50 border-b border-slate-100 flex-shrink-0">
        <div className="flex items-center gap-3">
          <div className="bg-blue-600 p-2 rounded-xl shadow-blue-500/20 shadow-lg">
            <ShoppingBag size={18} className="text-white" />
          </div>
          <span className="font-extrabold text-base tracking-tight">{t.brand}</span>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={() => setState(prev => ({ ...prev, lang: prev.lang === 'zh' ? 'en' : 'zh' }))} className="px-3 py-1.5 bg-slate-50 border border-slate-200 rounded-full text-[10px] font-black uppercase text-slate-500 flex items-center gap-2 hover:bg-white hover:border-blue-400 transition-all">
            <Globe size={12} />{state.lang === 'zh' ? 'English' : '中文'}
          </button>
        </div>
      </header>

      {/* APP MAIN CONTENT (100% RESPONSIVE) */}
      <main className="flex-1 overflow-y-auto pb-24 max-w-2xl mx-auto w-full px-4 pt-6">
        {state.activeTab === 'studio' && (
          <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-300">
            <div className="bg-white rounded-[2.5rem] p-6 shadow-sm space-y-6 border border-slate-100">
              <h2 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Smartphone size={16} className="text-blue-500" />{t.editorStudio}</h2>

              <div className="space-y-5">
                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-slate-400 uppercase">{t.productPhotos}</label>
                  <div className="flex flex-wrap gap-3">
                    {state.originalImages.map((img, i) => (
                      <div key={i} className="relative w-20 h-20 rounded-2xl overflow-hidden border border-slate-100 shadow-sm">
                        <img src={img} className="w-full h-full object-cover" />
                        <button onClick={() => setState(p => ({ ...p, originalImages: p.originalImages.filter((_, idx) => idx !== i) }))} className="absolute top-1 right-1 p-1 bg-black/40 text-white rounded-full"><X size={12} /></button>
                      </div>
                    ))}
                    {state.originalImages.length < 3 && (
                      <button onClick={() => fileInputRef.current?.click()} className="w-20 h-20 border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center text-slate-400 bg-slate-50/50 active:scale-95 transition-all">
                        <Plus size={20} /><span className="text-[8px] font-bold mt-1 uppercase">{t.uploadPrompt}</span>
                      </button>
                    )}
                  </div>
                  <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" multiple accept="image/*" />
                </div>

                <div className="space-y-2 pt-4 border-t border-slate-50">
                  <label className="text-[10px] font-bold text-slate-400 uppercase">{t.modelPhoto}</label>
                  <div className="flex items-center gap-4">
                    {state.modelImage ? (
                      <div className="relative w-20 h-20 rounded-2xl overflow-hidden border-2 border-emerald-400 shadow-sm">
                        <img src={state.modelImage} className="w-full h-full object-cover" />
                        <button onClick={() => setState(p => ({ ...p, modelImage: null }))} className="absolute top-1 right-1 p-1 bg-black/40 text-white rounded-full"><X size={12} /></button>
                      </div>
                    ) : (
                      <button onClick={() => modelInputRef.current?.click()} className="flex-1 h-12 border border-slate-200 bg-slate-50 rounded-2xl flex items-center justify-center gap-2 text-slate-500 text-[10px] font-bold uppercase active:bg-slate-100 transition-colors">
                        <Shirt size={14} className="text-emerald-500" />{t.uploadModelPrompt}
                      </button>
                    )}
                    <input type="file" ref={modelInputRef} onChange={handleModelUpload} className="hidden" accept="image/*" />
                    {!state.modelImage && <p className="flex-1 text-[9px] italic text-slate-400 leading-relaxed uppercase font-medium">{t.autoModelHint}</p>}
                  </div>
                </div>
              </div>

              <div className="space-y-5">
                <div className="space-y-1.5">
                  <div className="flex justify-between items-center px-1">
                    <label className="text-[10px] font-bold text-slate-400 uppercase">{t.productDesc}</label>
                    {state.isAnalyzingImage && <span className="text-[9px] text-blue-500 font-bold animate-pulse uppercase tracking-widest">{t.analyzingImage}</span>}
                  </div>
                  <textarea value={productDesc} onChange={(e) => setProductDesc(e.target.value)} rows={3} placeholder={t.productPlaceholder} className="w-full bg-slate-50 border border-slate-100 rounded-3xl p-4 text-xs font-semibold focus:outline-none focus:ring-2 focus:ring-blue-100 transition-all shadow-inner" />
                </div>

                <div className="space-y-2.5">
                  <div className="flex justify-between items-center px-1">
                    <label className="text-[10px] font-bold text-slate-400 uppercase">{t.potentialHashtags}</label>
                    <button onClick={suggestHashtags} disabled={!productDesc || state.isGeneratingHashtags} className="text-[9px] font-black text-blue-600 uppercase flex items-center gap-1 active:scale-95">{state.isGeneratingHashtags ? <Loader2 size={12} className="animate-spin" /> : <RotateCcw size={12} />}{t.suggestTags}</button>
                  </div>
                  <div className="flex flex-wrap gap-2 p-3 bg-slate-50 rounded-3xl min-h-[44px] shadow-inner">
                    {state.potentialHashtags.length > 0 ? state.potentialHashtags.map((tag, i) => (
                      <span key={i} className="px-3 py-1 bg-white border border-slate-100 text-[9px] font-black text-slate-500 rounded-xl shadow-sm">#{tag}</span>
                    )) : <span className="text-[9px] text-slate-300 italic p-1 uppercase">Waiting for assets...</span>}
                  </div>
                </div>

                <div className="space-y-2.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase">{t.publishPlatform}</label>
                  <div className="grid grid-cols-3 gap-1.5 bg-slate-100 p-1.5 rounded-3xl shadow-inner">
                    {(['xiaohongshu', 'instagram', 'facebook'] as Platform[]).map(p => (
                      <button key={p} onClick={() => setState(prev => ({ ...prev, activePlatform: p }))} className={`py-2 rounded-2xl text-[10px] font-bold transition-all flex items-center justify-center gap-1.5 ${state.activePlatform === p ? 'bg-white shadow-md text-blue-600' : 'text-slate-400 active:bg-slate-200'}`}>
                        {PLATFORM_CONFIG[p].icon}{PLATFORM_CONFIG[p].name[state.lang]}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="flex items-center justify-between py-3 border-y border-slate-50">
                  <div className="flex items-center gap-2"><Palette size={16} className="text-purple-400" /><label className="text-[10px] font-bold text-slate-400 uppercase">{t.isCustom}</label></div>
                  <button onClick={() => setState(p => ({ ...p, isCustomizable: !p.isCustomizable }))} className="transition-all active:scale-90">
                    {state.isCustomizable ? <ToggleRight className="text-blue-500" size={32} /> : <ToggleLeft className="text-slate-200" size={32} />}
                  </button>
                </div>

                <div className="space-y-2.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase">{t.voiceStyle}</label>
                  <div className="flex flex-wrap gap-2">
                    {VOICE_STYLES[state.activePlatform].map(s => (
                      <button key={s.id} onClick={() => setState(p => ({ ...p, selectedVoiceStyles: { ...p.selectedVoiceStyles, [p.activePlatform]: s.id } }))} className={`px-4 py-2 rounded-2xl text-[10px] font-bold border transition-all ${state.selectedVoiceStyles[state.activePlatform] === s.id ? 'bg-blue-600 border-blue-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-400 active:border-blue-300'}`}>{s.name[state.lang]}</button>
                    ))}
                  </div>
                </div>
              </div>

              <button onClick={() => generateAI()} disabled={state.isGenerating || state.originalImages.length === 0 || !productDesc} className={`w-full py-4.5 rounded-[2rem] font-black text-sm flex items-center justify-center gap-2 transition-all shadow-xl active:scale-95 ${state.isGenerating ? 'bg-slate-100 text-slate-300' : 'bg-blue-600 text-white shadow-blue-500/20 hover:bg-blue-700'}`}>
                {state.isGenerating ? <><Loader2 className="animate-spin" size={18} />{t.generating}</> : <><Sparkles size={18} />{t.generateBtn}</>}
              </button>
            </div>
          </div>
        )}

        {state.activeTab === 'results' && (
          <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-300">
            {!activeContent && !state.isGenerating ? (
              <div className="flex flex-col items-center justify-center py-20 text-slate-300 space-y-4">
                <div className="bg-white p-8 rounded-full shadow-inner"><Layout size={40} /></div>
                <p className="text-[10px] font-black uppercase tracking-widest">{t.outputSub}</p>
              </div>
            ) : state.isGenerating ? (
              <div className="flex flex-col items-center justify-center py-32 space-y-8">
                <div className="relative">
                  <div className="w-20 h-20 border-b-4 border-blue-600 rounded-full animate-spin" />
                  <div className="absolute inset-0 flex items-center justify-center"><RefreshCw className="text-blue-500 animate-pulse" size={24} /></div>
                </div>
                <div className="text-center">
                  <h3 className="font-black text-slate-700 text-lg tracking-tight">{t.generating}</h3>
                  <p className="text-[9px] font-black text-slate-400 uppercase mt-2 tracking-widest">Applying platform optimization</p>
                </div>
              </div>
            ) : (
              <>
                <div className="space-y-4">
                  <h3 className="text-[11px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2 px-1"><ImageIcon size={14} />{t.enhancedImg}</h3>
                  <div className="flex overflow-x-auto gap-4 pb-4 snap-x hide-scrollbar px-1">
                    {state.enhancedImages.map((img, i) => (
                      <div key={i} className="min-w-[240px] h-80 rounded-[2.5rem] overflow-hidden shadow-2xl snap-center relative group">
                        <img src={img} className="w-full h-full object-cover" />
                        <button onClick={() => { const l = document.createElement('a'); l.href = img; l.download = `IMG-${i}.png`; l.click(); }} className="absolute bottom-4 right-4 p-3 bg-white/90 backdrop-blur-md rounded-2xl shadow-lg active:scale-90"><Download size={18} /></button>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="bg-white rounded-[3rem] p-8 shadow-sm border border-slate-100 space-y-8 relative overflow-hidden">
                  <div className={`absolute top-0 left-0 w-full h-1.5 ${PLATFORM_CONFIG[state.activePlatform].color}`} />
                  <div className="flex justify-between items-center">
                    <div className="flex items-center gap-4">
                      <div className={`w-12 h-12 ${PLATFORM_CONFIG[state.activePlatform].color} rounded-[1.25rem] flex items-center justify-center text-xl shadow-lg`}>{PLATFORM_CONFIG[state.activePlatform].icon}</div>
                      <div>
                        <h4 className="font-black text-base">{PLATFORM_CONFIG[state.activePlatform].name[state.lang]}</h4>
                        <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Optimized Copy</p>
                      </div>
                    </div>
                    <button onClick={() => {
                        const tStr = `【${activeContent?.title}】\n\n${activeContent?.body}\n\n${activeContent?.hashtags.join(' ')}`;
                        copyToClipboard(tStr, 'all');
                    }} className="px-4 py-2 bg-blue-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest active:scale-90 shadow-xl shadow-blue-500/20">{copied === 'all' ? <Check size={14} /> : <Copy size={14} />}</button>
                  </div>

                  <div className="space-y-6">
                    <div className="space-y-2">
                      <div className="flex justify-between"><label className="text-[10px] font-black text-slate-300 uppercase">{t.suggestedTitle}</label><button onClick={() => copyToClipboard(activeContent?.title || '', 't')} className="text-slate-200 active:text-blue-500"><Copy size={12}/></button></div>
                      <div className="p-5 bg-slate-50 rounded-[2rem] text-sm font-black text-slate-800 shadow-inner leading-relaxed">{activeContent?.title}</div>
                    </div>
                    <div className="space-y-2">
                      <div className="flex justify-between"><label className="text-[10px] font-black text-slate-300 uppercase">{t.bodyText}</label><button onClick={() => copyToClipboard(activeContent?.body || '', 'b')} className="text-slate-200 active:text-blue-500"><Copy size={12}/></button></div>
                      <div className="p-5 bg-slate-50 rounded-[2rem] text-xs font-bold leading-relaxed text-slate-600 whitespace-pre-wrap shadow-inner">{activeContent?.body}</div>
                    </div>
                    <div className="flex flex-wrap gap-2 pt-2">
                      {activeContent?.hashtags.map((tag, i) => <span key={i} className="px-3 py-1 bg-blue-50 border border-blue-100 rounded-xl text-[10px] font-black text-blue-600 uppercase">#{tag}</span>)}
                    </div>
                  </div>

                  <div className="pt-8 border-t border-slate-50">
                    {!state.isFeedbackMode ? (
                      <button onClick={() => setState(p => ({ ...p, isFeedbackMode: true }))} className="flex items-center gap-2 text-[10px] font-black text-slate-400 hover:text-blue-600 uppercase transition-colors"><MessageSquarePlus size={16} />{t.notSatisfied}</button>
                    ) : (
                      <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                        <textarea value={feedbackText} onChange={(e) => setFeedbackText(e.target.value)} placeholder="E.g. Make it warmer, add more technical details..." className="w-full bg-slate-50 rounded-[2rem] p-5 text-xs font-bold shadow-inner focus:outline-none focus:ring-1 focus:ring-blue-100" />
                        <div className="flex gap-3">
                          <button onClick={() => generateAI(true)} className="flex-1 py-3.5 bg-blue-600 text-white rounded-2xl text-[11px] font-black uppercase shadow-xl active:scale-95">{t.submitFeedback}</button>
                          <button onClick={() => setState(p => ({ ...p, isFeedbackMode: false }))} className="px-6 py-3.5 bg-slate-100 text-slate-400 rounded-2xl text-[11px] font-black uppercase">{state.lang === 'zh' ? '取消' : 'Back'}</button>
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              </>
            )}
          </div>
        )}

        {state.activeTab === 'archive' && (
          <div className="space-y-5 animate-in slide-in-from-left-4 duration-300">
             <h2 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2 px-1 mb-6"><Library size={16} className="text-blue-500" />{t.archive}</h2>
             {state.history.length === 0 ? (
               <div className="flex flex-col items-center justify-center py-32 text-slate-300 opacity-40"><Clock size={48} /><p className="text-[10px] font-black uppercase tracking-widest mt-6">History Empty</p></div>
             ) : state.history.map(item => (
                <div key={item.id} onClick={() => setState(p => ({ ...p, originalImages: item.images, activeTab: 'results', content: { ...p.content, [item.platform]: item.content }, activePlatform: item.platform }))} className="bg-white p-4 rounded-[2rem] border border-slate-100 shadow-sm flex gap-4 active:bg-slate-50 transition-colors cursor-pointer">
                  <div className="w-16 h-16 rounded-2xl overflow-hidden shadow-md flex-shrink-0"><img src={item.images[0]} className="w-full h-full object-cover" /></div>
                  <div className="flex-1 min-w-0 flex flex-col justify-center">
                    <div className="flex justify-between items-center mb-1.5">
                      <span className={`text-[8px] font-black px-2 py-0.5 rounded-lg text-white ${PLATFORM_CONFIG[item.platform].color}`}>{PLATFORM_CONFIG[item.platform].name[state.lang]}</span>
                      <span className="text-[9px] text-slate-300 font-bold">{new Date(item.timestamp).toLocaleDateString()}</span>
                    </div>
                    <h5 className="text-[12px] font-black text-slate-800 truncate">{item.content.title}</h5>
                    <p className="text-[10px] text-slate-400 font-bold truncate italic">{item.desc}</p>
                  </div>
                </div>
             ))}
          </div>
        )}
      </main>

      {/* BOTTOM NAVIGATION (STICKY) */}
      <nav className="h-20 bg-white/90 backdrop-blur-xl border-t border-slate-100 flex items-center justify-around px-8 sticky bottom-0 z-[100] flex-shrink-0 shadow-2xl">
        <button onClick={() => setState(p => ({ ...p, activeTab: 'studio' }))} className={`flex flex-col items-center gap-1.5 transition-all ${state.activeTab === 'studio' ? 'text-blue-600' : 'text-slate-300'}`}>
          <div className={`p-2.5 rounded-2xl transition-colors ${state.activeTab === 'studio' ? 'bg-blue-50' : ''}`}><PlusSquare size={22} strokeWidth={state.activeTab === 'studio' ? 2.5 : 2} /></div>
          <span className="text-[9px] font-black uppercase tracking-widest">{t.studio}</span>
        </button>
        <button onClick={() => setState(p => ({ ...p, activeTab: 'results' }))} className={`flex flex-col items-center gap-1.5 transition-all ${state.activeTab === 'results' ? 'text-blue-600' : 'text-slate-300'}`}>
          <div className={`p-2.5 rounded-2xl transition-colors ${state.activeTab === 'results' ? 'bg-blue-50' : ''}`}><Sparkles size={22} strokeWidth={state.activeTab === 'results' ? 2.5 : 2} /></div>
          <span className="text-[9px] font-black uppercase tracking-widest">{t.results}</span>
        </button>
        <button onClick={() => setState(p => ({ ...p, activeTab: 'archive' }))} className={`flex flex-col items-center gap-1.5 transition-all ${state.activeTab === 'archive' ? 'text-blue-600' : 'text-slate-300'}`}>
          <div className={`p-2.5 rounded-2xl transition-colors ${state.activeTab === 'archive' ? 'bg-blue-50' : ''}`}><Library size={22} strokeWidth={state.activeTab === 'archive' ? 2.5 : 2} /></div>
          <span className="text-[9px] font-black uppercase tracking-widest">{t.archive}</span>
        </button>
      </nav>

      {/* GLOBAL LOADING OVERLAY */}
      {state.isGenerating && (
        <div className="fixed inset-0 z-[200] bg-white/60 backdrop-blur-md flex flex-col items-center justify-center space-y-6 animate-in fade-in duration-300">
           <div className="bg-white p-10 rounded-[3.5rem] shadow-2xl flex flex-col items-center space-y-6">
              <div className="w-14 h-14 border-4 border-blue-100 border-b-blue-600 rounded-full animate-spin" />
              <p className="text-[11px] font-black text-blue-600 uppercase tracking-[0.25em]">{t.generating}</p>
           </div>
        </div>
      )}
    </div>
  );
};

const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(<App />);
}

import React, { useState, useRef, useEffect } from 'react';
