const App = () => {
  const [state, setState] = useState<AppState>({
    originalImages: [],
    modelImage: null,
    enhancedImages: [],
    content: { xiaohongshu: null, instagram: null, facebook: null },
    isGenerating: false,
    activePlatform: 'xiaohongshu',
    stylePreference: '',
    selectedVoiceStyles: {
      xiaohongshu: 'storytelling',
      instagram: 'minimalist',
      facebook: 'friendly_share'
    },
    isCustomizable: false,
    lang: 'zh',
    potentialHashtags: [],
    isGeneratingHashtags: false,
    isAnalyzingImage: false,
    activeTab: 'studio',
    history: [],
    isFeedbackMode: false
  });
  const [productDesc, setProductDesc] = useState('');
  const [feedbackText, setFeedbackText] = useState('');
  const [copied, setCopied] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const modelInputRef = useRef<HTMLInputElement>(null);

  const t = TRANSLATIONS[state.lang];

  useEffect(() => {
    const triggerAutoDescription = async () => {
      if (state.originalImages.length > 0 && !productDesc && !state.isAnalyzingImage) {
        setState(prev => ({ ...prev, isAnalyzingImage: true }));
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        try {
          const visionPrompt = state.lang === 'zh' 
            ? "识别图中展示的一组产品。请基于这些图片，用简短的关键词组合作为描述。不要写长句，只返回2-4个核心词。"
            : "Identify the product in these images. Provide a brief combination of keywords. Return ONLY 2-4 keywords.";

          const parts = state.originalImages.map(img => ({
            inlineData: { data: img.split(',')[1] || '', mimeType: 'image/png' } as GenAIBlob
          }));
          const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: { parts: [...parts, { text: visionPrompt }] }
          });
          if (response.text) setProductDesc(response.text.trim());
        } catch (err) {
          console.error("Auto-description error:", err);
        } finally {
          setState(prev => ({ ...prev, isAnalyzingImage: false }));
        }
      }
    };
    triggerAutoDescription();
  }, [state.originalImages.length, state.isAnalyzingImage, state.lang, productDesc]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      const remainingSlots = 3 - state.originalImages.length;
      const filesToProcess = Array.from(files).slice(0, remainingSlots);
      filesToProcess.forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          setState(prev => ({ 
            ...prev, 
            originalImages: [...prev.originalImages, reader.result as string].slice(0, 3)
          }));
        };
        reader.readAsDataURL(file);
      });
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleModelUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setState(prev => ({ ...prev, modelImage: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
    if (modelInputRef.current) modelInputRef.current.value = '';
  };

  const suggestHashtags = async () => {
    if (!productDesc) return;
    setState(prev => ({ ...prev, isGeneratingHashtags: true }));
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const prompt = `Based on: "${productDesc}", extract 3-5 highly relevant hashtags in ${state.lang === 'zh' ? 'Chinese' : 'English'}. Return ONLY a JSON array of strings.`;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: 'application/json' }
      });
      const tags = JSON.parse(response.text || '[]');
      setState(prev => ({ ...prev, potentialHashtags: Array.isArray(tags) ? tags : [], isGeneratingHashtags: false }));
    } catch (err) {
      setState(prev => ({ ...prev, isGeneratingHashtags: false }));
    }
  };

  const generateAI = async (withFeedback: boolean = false) => {
    if (state.originalImages.length === 0 || !productDesc) return;
    setState(prev => ({ ...prev, isGenerating: true }));

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const styleContext = state.stylePreference ? `Style: ${state.stylePreference}.` : "High-end social media visuals.";
      const keywordContext = state.potentialHashtags.length > 0 ? `Tags: ${state.potentialHashtags.join(', ')}.` : "";
      const customContext = state.isCustomizable ? "STRESS that the product is CUSTOMIZABLE and bespoke." : "";
      const feedbackContext = withFeedback ? `User requested changes: "${feedbackText}".` : "";
      const noTextInstruction = "IMPORTANT: THE GENERATED IMAGE MUST NOT CONTAIN ANY TEXT, LOGOS, OR WATERMARKS. JUST A CLEAN PHOTO.";

      const primaryProductBase64 = state.originalImages[0].split(',')[1] || '';
      const modelBase64Raw = state.modelImage ? state.modelImage.split(',')[1] : null;

      const baseImagePrompt = `Clean professional lifestyle photo for ${PLATFORM_CONFIG[state.activePlatform].name.en}. ${styleContext} ${keywordContext} ${customContext} ${feedbackContext} ${noTextInstruction}`;

      let contentsForImageGen: any[] = [];
      if (modelBase64Raw) {
        contentsForImageGen = [
          {
            parts: [
              { inlineData: { data: modelBase64Raw, mimeType: 'image/png' } as GenAIBlob },
              { inlineData: { data: primaryProductBase64, mimeType: 'image/png' } as GenAIBlob },
              { text: `VIRTUAL TRY-ON: Show this model wearing this product. ${baseImagePrompt}` }
            ]
          },
          {
            parts: [
              { inlineData: { data: modelBase64Raw, mimeType: 'image/png' } as GenAIBlob },
              { inlineData: { data: primaryProductBase64, mimeType: 'image/png' } as GenAIBlob },
              { text: `A different elegant pose for the same model. ${baseImagePrompt}` }
            ]
          }
        ];
      } else {
        contentsForImageGen = [
          {
            parts: [
              { inlineData: { data: primaryProductBase64, mimeType: 'image/png' } as GenAIBlob },
              { text: `Modern model showcasing this product. ${baseImagePrompt}` }
            ]
          },
          {
            parts: [
              { inlineData: { data: primaryProductBase64, mimeType: 'image/png' } as GenAIBlob },
              { text: `A high-end product lifestyle shot. ${baseImagePrompt}` }
            ]
          }
        ];
      }

      const imagePromises: Promise<GenerateContentResponse>[] = contentsForImageGen.map(c => ai.models.generateContent({ 
        model: 'gemini-2.5-flash-image', 
        contents: c 
      }));

      const textPrompt = `
        Language: ${state.lang === 'zh' ? 'Chinese' : 'English'}
        Product: ${productDesc}
        Platform: ${PLATFORM_CONFIG[state.activePlatform].name.en}
        Tone: ${VOICE_STYLES[state.activePlatform].find(v => v.id === state.selectedVoiceStyles[state.activePlatform])?.name.en}
        ${customContext}
        ${feedbackContext}
        Return JSON ONLY: { "xiaohongshu": { "title": "...", "body": "...", "hashtags": [] }, "instagram": { ... }, "facebook": { ... } }
      `;

      const textParts = state.originalImages.map(img => ({ inlineData: { data: img.split(',')[1] || '', mimeType: 'image/png' } as GenAIBlob }));
      const textPromise: Promise<GenerateContentResponse> = ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts: [...textParts, { text: textPrompt }] },
        config: { responseMimeType: 'application/json' }
      });

      const results: GenerateContentResponse[] = await Promise.all([...imagePromises, textPromise]);

      const newImages: string[] = [];
      results.slice(0, 2).forEach(res => {
        const parts = res.candidates?.[0]?.content?.parts;
        if (parts) {
          for (const part of parts) {
            if (part.inlineData) {
              const base64Data = (part.inlineData as GenAIBlob).data;
              newImages.push(`data:image/png;base64,${base64Data}`);
              break;
            }
          }
        }
      });

      const content = JSON.parse(results[2].text || '{}');
      const activeData = content[state.activePlatform] || { title: "", body: "", hashtags: [] };

      const newHistoryItem: HistoryItem = {
        id: Math.random().toString(36).substr(2, 9),
        images: state.originalImages,
        modelImage: state.modelImage,
        desc: productDesc,
        platform: state.activePlatform,
        content: activeData,
        timestamp: Date.now()
      };

      setState(prev => ({ 
        ...prev, 
        enhancedImages: newImages, 
        content: { ...prev.content, ...content }, 
        isGenerating: false, 
        activeTab: 'results',
        history: [newHistoryItem, ...prev.history],
        isFeedbackMode: false 
      }));
      setFeedbackText('');
    } catch (err) {
      console.error(err);
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const copyToClipboard = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopied(id);
    setTimeout(() => setCopied(null), 2000);
  };

  const activeContent = state.content[state.activePlatform];

  return (
    <div className="min-h-screen bg-[#F1F5F9] flex items-center justify-center p-4">
      {/* IPHONE 16 CONTAINER (FIXED SIZE) */}
      <div className="relative w-[390px] h-[844px] bg-white rounded-[3.5rem] shadow-[0_0_80px_rgba(0,0,0,0.15)] border-[12px] border-black overflow-hidden flex flex-col">

        {/* DYNAMIC ISLAND */}
        <div className="absolute top-2 left-1/2 -translate-x-1/2 w-32 h-8 bg-black rounded-full z-[100] flex items-center justify-center gap-2 overflow-hidden">
          <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse"></div>
          <span className="text-[10px] font-bold text-white uppercase tracking-tighter opacity-80">AI Active</span>
        </div>

        {/* STATUS BAR SPACE */}
        <div className="h-10 w-full flex-shrink-0"></div>

        {/* APP HEADER */}
        <header className="h-14 bg-white/80 backdrop-blur-xl flex items-center justify-between px-6 flex-shrink-0 border-b border-slate-100">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 p-1.5 rounded-lg shadow-blue-500/20 shadow-lg">
              <ShoppingBag size={14} className="text-white" />
            </div>
            <span className="font-extrabold text-[12px] tracking-tight">{t.brand}</span>
          </div>
          <button onClick={() => setState(prev => ({ ...prev, lang: prev.lang === 'zh' ? 'en' : 'zh' }))} className="px-2 py-1 bg-slate-50 border border-slate-200 rounded-full text-[9px] font-black uppercase text-slate-500 flex items-center gap-1">
            <Globe size={10} />{state.lang === 'zh' ? 'EN' : 'CN'}
          </button>
        </header>

        {/* APP SCROLL CONTENT */}
        <main className="flex-1 overflow-y-auto pb-24 scroll-smooth">
          {state.activeTab === 'studio' && (
            <div className="p-4 space-y-5 animate-in slide-in-from-bottom-4 duration-300">
              <div className="bg-white rounded-3xl p-5 shadow-sm space-y-5 border border-slate-100">
                <h2 className="text-[11px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Smartphone size={14} className="text-blue-500" />{t.editorStudio}</h2>

                <div className="space-y-4">
                  <div className="space-y-2">
                    <label className="text-[9px] font-bold text-slate-400 uppercase">{t.productPhotos}</label>
                    <div className="flex gap-2">
                      {state.originalImages.map((img, i) => (
                        <div key={i} className="relative w-14 h-14 rounded-2xl overflow-hidden border border-slate-100 shadow-sm">
                          <img src={img} className="w-full h-full object-cover" />
                          <button onClick={() => setState(p => ({ ...p, originalImages: p.originalImages.filter((_, idx) => idx !== i) }))} className="absolute top-0.5 right-0.5 p-0.5 bg-black/40 text-white rounded-full"><X size={10} /></button>
                        </div>
                      ))}
                      {state.originalImages.length < 3 && (
                        <button onClick={() => fileInputRef.current?.click()} className="w-14 h-14 border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center text-slate-400 bg-slate-50/50 active:scale-95 transition-all">
                          <Plus size={16} /><span className="text-[7px] font-bold mt-1 uppercase">{t.uploadPrompt}</span>
                        </button>
                      )}
                    </div>
                    <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" multiple accept="image/*" />
                  </div>

                  <div className="space-y-2 pt-2 border-t border-slate-50">
                    <label className="text-[9px] font-bold text-slate-400 uppercase">{t.modelPhoto}</label>
                    <div className="flex items-center gap-3">
                      {state.modelImage ? (
                        <div className="relative w-14 h-14 rounded-2xl overflow-hidden border-2 border-emerald-400 shadow-sm">
                          <img src={state.modelImage} className="w-full h-full object-cover" />
                          <button onClick={() => setState(p => ({ ...p, modelImage: null }))} className="absolute top-0.5 right-0.5 p-0.5 bg-black/40 text-white rounded-full"><X size={10} /></button>
                        </div>
                      ) : (
                        <button onClick={() => modelInputRef.current?.click()} className="flex-1 h-10 border border-slate-200 bg-slate-50 rounded-2xl flex items-center justify-center gap-2 text-slate-500 text-[9px] font-bold uppercase active:bg-slate-100 transition-colors">
                          <Shirt size={12} className="text-emerald-500" />{t.uploadModelPrompt}
                        </button>
                      )}
                      <input type="file" ref={modelInputRef} onChange={handleModelUpload} className="hidden" accept="image/*" />
                      {!state.modelImage && <p className="flex-1 text-[7px] italic text-slate-400 leading-tight uppercase font-medium">{t.autoModelHint}</p>}
                    </div>
                  </div>
                </div>

                <div className="space-y-4">
                  <div className="space-y-1">
                    <div className="flex justify-between items-center px-1">
                      <label className="text-[9px] font-bold text-slate-400 uppercase">{t.productDesc}</label>
                      {state.isAnalyzingImage && <span className="text-[7px] text-blue-500 font-bold animate-pulse uppercase tracking-widest">{t.analyzingImage}</span>}
                    </div>
                    <textarea value={productDesc} onChange={(e) => setProductDesc(e.target.value)} rows={2} placeholder={t.productPlaceholder} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-[11px] font-semibold focus:outline-none focus:ring-2 focus:ring-blue-100 transition-all shadow-inner" />
                  </div>

                  <div className="space-y-2">
                    <div className="flex justify-between items-center px-1">
                      <label className="text-[9px] font-bold text-slate-400 uppercase">{t.potentialHashtags}</label>
                      <button onClick={suggestHashtags} disabled={!productDesc || state.isGeneratingHashtags} className="text-[8px] font-black text-blue-600 uppercase flex items-center gap-1 active:scale-95">{state.isGeneratingHashtags ? <Loader2 size={10} className="animate-spin" /> : <RotateCcw size={10} />}{t.suggestTags}</button>
                    </div>
                    <div className="flex flex-wrap gap-1.5 p-2 bg-slate-50 rounded-2xl min-h-[36px] shadow-inner">
                      {state.potentialHashtags.length > 0 ? state.potentialHashtags.map((tag, i) => (
                        <span key={i} className="px-2 py-0.5 bg-white border border-slate-100 text-[8px] font-black text-slate-500 rounded-lg shadow-sm">#{tag}</span>
                      )) : <span className="text-[7px] text-slate-300 italic p-1 uppercase">Analysis pending...</span>}
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-[9px] font-bold text-slate-400 uppercase">{t.publishPlatform}</label>
                    <div className="grid grid-cols-3 gap-1 bg-slate-100 p-1 rounded-2xl shadow-inner">
                      {(['xiaohongshu', 'instagram', 'facebook'] as Platform[]).map(p => (
                        <button key={p} onClick={() => setState(prev => ({ ...prev, activePlatform: p }))} className={`py-1.5 rounded-xl text-[9px] font-bold transition-all flex items-center justify-center gap-1 ${state.activePlatform === p ? 'bg-white shadow-md text-blue-600' : 'text-slate-400 active:bg-slate-200'}`}>
                          {PLATFORM_CONFIG[p].icon}{PLATFORM_CONFIG[p].name[state.lang]}
                        </button>
                      ))}
                    </div>
                  </div>

                  <div className="flex items-center justify-between py-2 border-y border-slate-50">
                    <div className="flex items-center gap-2"><Palette size={14} className="text-purple-400" /><label className="text-[9px] font-bold text-slate-400 uppercase">{t.isCustom}</label></div>
                    <button onClick={() => setState(p => ({ ...p, isCustomizable: !p.isCustomizable }))} className="transition-all active:scale-90">
                      {state.isCustomizable ? <ToggleRight className="text-blue-500" size={28} /> : <ToggleLeft className="text-slate-200" size={28} />}
                    </button>
                  </div>

                  <div className="space-y-2">
                    <label className="text-[9px] font-bold text-slate-400 uppercase">{t.voiceStyle}</label>
                    <div className="flex flex-wrap gap-1.5">
                      {VOICE_STYLES[state.activePlatform].map(s => (
                        <button key={s.id} onClick={() => setState(p => ({ ...p, selectedVoiceStyles: { ...p.selectedVoiceStyles, [p.activePlatform]: s.id } }))} className={`px-2.5 py-1 rounded-xl text-[9px] font-bold border transition-all ${state.selectedVoiceStyles[state.activePlatform] === s.id ? 'bg-blue-600 border-blue-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-400 active:border-blue-300'}`}>{s.name[state.lang]}</button>
                      ))}
                    </div>
                  </div>
                </div>

                <button onClick={() => generateAI()} disabled={state.isGenerating || state.originalImages.length === 0 || !productDesc} className={`w-full py-3.5 rounded-2xl font-black text-[12px] flex items-center justify-center gap-2 transition-all shadow-lg active:scale-95 ${state.isGenerating ? 'bg-slate-100 text-slate-300' : 'bg-blue-600 text-white shadow-blue-500/20 hover:bg-blue-700'}`}>
                  {state.isGenerating ? <><Loader2 className="animate-spin" size={14} />{t.generating}</> : <><Sparkles size={14} />{t.generateBtn}</>}
                </button>
              </div>
            </div>
          )}

          {state.activeTab === 'results' && (
            <div className="p-4 space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
              {!activeContent && !state.isGenerating ? (
                <div className="flex flex-col items-center justify-center pt-20 text-slate-300 space-y-4">
                  <div className="bg-white p-6 rounded-full shadow-inner"><Layout size={32} /></div>
                  <p className="text-[9px] font-black uppercase tracking-widest">{t.outputSub}</p>
                </div>
              ) : state.isGenerating ? (
                <div className="flex flex-col items-center justify-center pt-24 space-y-6">
                  <div className="relative"><div className="w-16 h-16 border-b-2 border-blue-600 rounded-full animate-spin" /><div className="absolute inset-0 flex items-center justify-center"><RefreshCw className="text-blue-500 animate-pulse" size={20} /></div></div>
                  <div className="text-center"><h3 className="font-black text-slate-700 tracking-tight">{t.generating}</h3><p className="text-[8px] font-black text-slate-400 uppercase mt-1 tracking-widest">Optimizing platform dynamics</p></div>
                </div>
              ) : (
                <>
                  <div className="space-y-3">
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2 px-1"><ImageIcon size={12} />{t.enhancedImg}</h3>
                    <div className="flex overflow-x-auto gap-3 pb-2 snap-x hide-scrollbar px-1">
                      {state.enhancedImages.map((img, i) => (
                        <div key={i} className="min-w-[180px] h-56 rounded-3xl overflow-hidden shadow-lg snap-center relative group">
                          <img src={img} className="w-full h-full object-cover" />
                          <button onClick={() => { const l = document.createElement('a'); l.href = img; l.download = `IMG-${i}.png`; l.click(); }} className="absolute bottom-3 right-3 p-2 bg-white/90 backdrop-blur rounded-xl shadow-md active:scale-90"><Download size={14} /></button>
                        </div>
                      ))}
                    </div>
                  </div>

                  <div className="bg-white rounded-[2.5rem] p-6 shadow-sm border border-slate-100 space-y-6 relative overflow-hidden">
                    <div className={`absolute top-0 left-0 w-full h-1 ${PLATFORM_CONFIG[state.activePlatform].color}`} />
                    <div className="flex justify-between items-center">
                      <div className="flex items-center gap-3"><div className={`w-9 h-9 ${PLATFORM_CONFIG[state.activePlatform].color} rounded-xl flex items-center justify-center text-sm shadow-md`}>{PLATFORM_CONFIG[state.activePlatform].icon}</div><div><h4 className="font-black text-[12px]">{PLATFORM_CONFIG[state.activePlatform].name[state.lang]}</h4><p className="text-[7px] font-black text-slate-400 uppercase tracking-widest">AI Content Generation</p></div></div>
                      <button onClick={() => {
                          const tStr = `【${activeContent?.title}】\n\n${activeContent?.body}\n\n${activeContent?.hashtags.join(' ')}`;
                          copyToClipboard(tStr, 'all');
                      }} className="px-2.5 py-1 bg-blue-600 text-white rounded-lg text-[8px] font-black uppercase tracking-widest active:scale-90 shadow-lg shadow-blue-500/20">{copied === 'all' ? <Check size={10} /> : <Copy size={10} />}</button>
                    </div>

                    <div className="space-y-4">
                      <div className="space-y-1.5">
                        <div className="flex justify-between"><label className="text-[8px] font-black text-slate-300 uppercase">{t.suggestedTitle}</label><button onClick={() => copyToClipboard(activeContent?.title || '', 't')} className="text-slate-200 active:text-blue-500"><Copy size={10}/></button></div>
                        <div className="p-3 bg-slate-50 rounded-xl text-[12px] font-black text-slate-800 shadow-inner">{activeContent?.title}</div>
                      </div>
                      <div className="space-y-1.5">
                        <div className="flex justify-between"><label className="text-[8px] font-black text-slate-300 uppercase">{t.bodyText}</label><button onClick={() => copyToClipboard(activeContent?.body || '', 'b')} className="text-slate-200 active:text-blue-500"><Copy size={10}/></button></div>
                        <div className="p-3 bg-slate-50 rounded-xl text-[10px] font-bold leading-relaxed text-slate-600 whitespace-pre-wrap shadow-inner">{activeContent?.body}</div>
                      </div>
                      <div className="flex flex-wrap gap-1 pt-2">
                        {activeContent?.hashtags.map((tag, i) => <span key={i} className="px-2 py-0.5 bg-blue-50 border border-blue-100 rounded-lg text-[8px] font-black text-blue-600 uppercase">#{tag}</span>)}
                      </div>
                    </div>

                    <div className="pt-6 border-t border-slate-50">
                      {!state.isFeedbackMode ? (
                        <button onClick={() => setState(p => ({ ...p, isFeedbackMode: true }))} className="flex items-center gap-2 text-[8px] font-black text-slate-300 uppercase active:text-blue-500 transition-colors"><MessageSquarePlus size={12} />{t.notSatisfied}</button>
                      ) : (
                        <div className="space-y-3 animate-in fade-in slide-in-from-top-2">
                          <textarea value={feedbackText} onChange={(e) => setFeedbackText(e.target.value)} placeholder="How can I improve this?" className="w-full bg-slate-50 rounded-xl p-3 text-[10px] font-bold shadow-inner focus:outline-none focus:ring-1 focus:ring-blue-100" />
                          <div className="flex gap-2">
                            <button onClick={() => generateAI(true)} className="flex-1 py-2.5 bg-blue-600 text-white rounded-lg text-[9px] font-black uppercase shadow-lg active:scale-95">{t.submitFeedback}</button>
                            <button onClick={() => setState(p => ({ ...p, isFeedbackMode: false }))} className="px-3 py-2.5 bg-slate-100 text-slate-400 rounded-lg text-[9px] font-black uppercase">{state.lang === 'zh' ? '取消' : 'Back'}</button>
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                </>
              )}
            </div>
          )}

          {state.activeTab === 'archive' && (
            <div className="p-4 space-y-4 animate-in slide-in-from-left-4 duration-300">
               <h2 className="text-[11px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2 px-1 mb-4"><Library size={14} className="text-blue-500" />{t.archive}</h2>
               {state.history.length === 0 ? (
                 <div className="flex flex-col items-center justify-center pt-20 text-slate-300 opacity-40"><Clock size={32} /><p className="text-[9px] font-black uppercase tracking-widest mt-4">No creations yet</p></div>
               ) : state.history.map(item => (
                  <div key={item.id} onClick={() => setState(p => ({ ...p, originalImages: item.images, activeTab: 'results', content: { ...p.content, [item.platform]: item.content }, activePlatform: item.platform }))} className="bg-white p-3 rounded-2xl border border-slate-100 shadow-sm flex gap-3 active:bg-slate-50 transition-colors cursor-pointer">
                    <div className="w-12 h-12 rounded-xl overflow-hidden shadow-sm flex-shrink-0"><img src={item.images[0]} className="w-full h-full object-cover" /></div>
                    <div className="flex-1 min-w-0 flex flex-col justify-center">
                      <div className="flex justify-between items-center mb-1.5">
                        <span className={`text-[7px] font-black px-1 py-0.5 rounded text-white ${PLATFORM_CONFIG[item.platform].color}`}>{PLATFORM_CONFIG[item.platform].name[state.lang]}</span>
                        <span className="text-[7px] text-slate-300 font-bold">{new Date(item.timestamp).toLocaleDateString()}</span>
                      </div>
                      <h5 className="text-[10px] font-black text-slate-800 truncate">{item.content.title}</h5>
                      <p className="text-[8px] text-slate-400 font-bold truncate italic">{item.desc}</p>
                    </div>
                  </div>
               ))}
            </div>
          )}
        </main>

        {/* MOBILE BOTTOM NAVIGATION */}
        <nav className="h-20 bg-white/90 backdrop-blur-xl border-t border-slate-100 flex items-center justify-around px-4 sticky bottom-0 z-50 flex-shrink-0 shadow-lg">
          <button onClick={() => setState(p => ({ ...p, activeTab: 'studio' }))} className={`flex flex-col items-center gap-1 transition-all ${state.activeTab === 'studio' ? 'text-blue-600' : 'text-slate-300'}`}>
            <div className={`p-2 rounded-xl transition-colors ${state.activeTab === 'studio' ? 'bg-blue-50' : ''}`}><PlusSquare size={18} strokeWidth={state.activeTab === 'studio' ? 2.5 : 2} /></div>
            <span className="text-[7px] font-black uppercase tracking-widest">{t.studio}</span>
          </button>
          <button onClick={() => setState(p => ({ ...p, activeTab: 'results' }))} className={`flex flex-col items-center gap-1 transition-all ${state.activeTab === 'results' ? 'text-blue-600' : 'text-slate-300'}`}>
            <div className={`p-2 rounded-xl transition-colors ${state.activeTab === 'results' ? 'bg-blue-50' : ''}`}><Sparkles size={18} strokeWidth={state.activeTab === 'results' ? 2.5 : 2} /></div>
            <span className="text-[7px] font-black uppercase tracking-widest">{t.results}</span>
          </button>
          <button onClick={() => setState(p => ({ ...p, activeTab: 'archive' }))} className={`flex flex-col items-center gap-1 transition-all ${state.activeTab === 'archive' ? 'text-blue-600' : 'text-slate-300'}`}>
            <div className={`p-2 rounded-xl transition-colors ${state.activeTab === 'archive' ? 'bg-blue-50' : ''}`}><Library size={18} strokeWidth={state.activeTab === 'archive' ? 2.5 : 2} /></div>
            <span className="text-[7px] font-black uppercase tracking-widest">{t.archive}</span>
          </button>
