          <span className="text-[9px] font-black uppercase tracking-widest">{t.results}</span>
        </button>
        <button onClick={() => setState(p => ({ ...p, activeTab: 'archive' }))} className={`flex flex-col items-center gap-1.5 transition-all ${state.activeTab === 'archive' ? 'text-blue-600' : 'text-slate-300'}`}>
          <div className={`p-2 rounded-xl transition-colors ${state.activeTab === 'archive' ? 'bg-blue-50' : ''}`}><Library size={22} strokeWidth={state.activeTab === 'archive' ? 2.5 : 2} /></div>
          <span className="text-[9px] font-black uppercase tracking-widest">{t.archive}</span>
