// --- Types & Config ---
type Platform = 'xiaohongshu' | 'instagram' | 'facebook';
type Language = 'zh' | 'en';
type AppTab = 'studio' | 'results' | 'archive' | 'architecture';

interface GeneratedContent {
  title: string;
  body: string;
  hashtags: string[];
}

interface HistoryItem {
  id: string;
  images: string[];
  modelImage: string | null;
  desc: string;
  platform: Platform;
  content: GeneratedContent;
  timestamp: number;
}

interface AppState {
  originalImages: string[];
  modelImage: string | null;
  enhancedImages: string[];
  content: Record<Platform, GeneratedContent | null>;
  isGenerating: boolean;
  activePlatform: Platform;
  stylePreference: string;
  selectedVoiceStyles: Record<Platform, string>;
  isCustomizable: boolean;
  lang: Language;
  potentialHashtags: string[];
  isGeneratingHashtags: boolean;
  isAnalyzingImage: boolean;
  activeTab: AppTab;
  history: HistoryItem[];
  isFeedbackMode: boolean;
}

