// Explicitly import Part from @google/genai to avoid collision with browser's native Blob
import { GoogleGenAI, GenerateContentResponse, Part } from "@google/genai";

// --- Types & Config ---
type Platform = 'xiaohongshu' | 'instagram' | 'facebook';
